{
  "name": "FlashMind PDF",
  "description": "Upload a PDF document and instantly generate interactive study flashcards using Gemini AI."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface FlashcardData {
  id: string;
  question: string;
  answer: string;
  category?: string;
}

export enum AppState {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  STUDYING = 'STUDYING',
  ERROR = 'ERROR'
}

export interface ProcessingStatus {
  step: string;
  progress: number;
}

import { GoogleGenAI, Type } from "@google/genai";
import { FlashcardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateFlashcardsFromPdf = async (
  base64Pdf: string,
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question for the flashcard. Be concise but specific."
          },
          answer: {
            type: Type.STRING,
            description: "The answer to the question. Accurate and easy to memorize."
          },
          category: {
            type: Type.STRING,
            description: "A short tag or category for this card (e.g., 'Definitions', 'Dates', 'Concepts')."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached PDF document. 
      Create a set of comprehensive flashcards (at least 10, up to 20) based on the key concepts, definitions, and important details found in the text.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}
      Ensure the questions are clear and the answers are accurate.
    `;

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Pdf,
              mimeType: "application/pdf",
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    const parsedData = JSON.parse(jsonText);

    // Add IDs to the cards for React keys
    return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
      ...card,
      id: `card-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Upload, FileText, Loader2, AlertCircle } from 'lucide-react';

interface FileUploadProps {
  onFileSelect: (file: File) => void;
  isLoading: boolean;
  error?: string | null;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFileSelect, isLoading, error }) => {
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      validateAndPassFile(e.dataTransfer.files[0]);
    }
  };

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      validateAndPassFile(e.target.files[0]);
    }
  };

  const validateAndPassFile = (file: File) => {
    if (file.type !== 'application/pdf') {
      alert('Please upload a valid PDF file.');
      return;
    }
    onFileSelect(file);
  };

  const triggerFileInput = () => {
    fileInputRef.current?.click();
  };

  return (
    <div className="w-full max-w-xl mx-auto">
      <div
        className={`relative border-2 border-dashed rounded-2xl p-10 transition-all duration-300 ease-in-out text-center cursor-pointer overflow-hidden
          ${isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.02]' 
            : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50 bg-white'
          }
          ${isLoading ? 'opacity-50 pointer-events-none' : ''}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={triggerFileInput}
      >
        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept="application/pdf"
          onChange={handleFileInput}
        />

        <div className="flex flex-col items-center justify-center space-y-4">
          <div className={`p-4 rounded-full ${isDragging ? 'bg-indigo-100' : 'bg-slate-100'}`}>
            {isLoading ? (
              <Loader2 className="w-8 h-8 text-indigo-600 animate-spin" />
            ) : (
              <Upload className={`w-8 h-8 ${isDragging ? 'text-indigo-600' : 'text-slate-400'}`} />
            )}
          </div>

          <div className="space-y-2">
            <h3 className="text-lg font-semibold text-slate-700">
              {isLoading ? 'Processing Document...' : 'Upload your PDF'}
            </h3>
            <p className="text-sm text-slate-500 max-w-xs mx-auto">
              {isLoading 
                ? 'Gemini is reading your file and generating flashcards.' 
                : 'Drag and drop your PDF here, or click to browse.'}
            </p>
          </div>
        </div>
      </div>

      {error && (
        <div className="mt-6 p-4 bg-red-50 border border-red-200 rounded-xl flex items-start gap-3 text-red-700 animate-in fade-in slide-in-from-bottom-2">
          <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <p className="text-sm">{error}</p>
        </div>
      )}

      {!isLoading && !error && (
        <div className="mt-8 flex justify-center gap-8 text-slate-400">
          <div className="flex items-center gap-2">
            <FileText className="w-4 h-4" />
            <span className="text-xs font-medium">PDF Support</span>
          </div>
          <div className="flex items-center gap-2">
            <svg className="w-4 h-4" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm-1 17.93c-3.95-.49-7-3.85-7-7.93 0-.62.08-1.21.21-1.79L9 15v1c0 1.1.9 2 2 2v1.93zm6.9-2.54c-.26-.81-1-1.39-1.9-1.39h-1v-3c0-.55-.45-1-1-1H8v-2h2c.55 0 1-.45 1-1V7h2c1.1 0 2-.9 2-2v-.41c2.93 1.19 5 4.06 5 7.41 0 2.08-.8 3.97-2.1 5.39z"/></svg>
            <span className="text-xs font-medium">Gemini 3 Flash</span>
          </div>
        </div>
      )}
    </div>
  );
};

