import React, { useState, useEffect } from 'react';
import { ChevronLeft, ChevronRight, RotateCcw, Shuffle, Layers } from 'lucide-react';
import { FlashcardData } from '../types';

interface FlashcardDeckProps {
  cards: FlashcardData[];
  onReset: () => void;
}

const FlashcardDeck: React.FC<FlashcardDeckProps> = ({ cards: initialCards, onReset }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [cards, setCards] = useState<FlashcardData[]>(initialCards);

  // Reset flip state when changing cards
  useEffect(() => {
    setIsFlipped(false);
  }, [currentIndex]);

  const handleNext = () => {
    if (currentIndex < cards.length - 1) {
      setCurrentIndex((prev) => prev + 1);
    }
  };

  const handlePrev = () => {
    if (currentIndex > 0) {
      setCurrentIndex((prev) => prev - 1);
    }
  };

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const handleShuffle = () => {
    const shuffled = [...cards].sort(() => Math.random() - 0.5);
    setCards(shuffled);
    setCurrentIndex(0);
    setIsFlipped(false);
  };

  const currentCard = cards[currentIndex];
  const progress = ((currentIndex + 1) / cards.length) * 100;

  return (
    <div className="w-full max-w-2xl mx-auto flex flex-col h-full min-h-[600px]">
      {/* Header Controls */}
      <div className="flex items-center justify-between mb-6 px-4">
        <button 
          onClick={onReset}
          className="text-sm font-medium text-slate-500 hover:text-indigo-600 flex items-center gap-1 transition-colors"
        >
          <Layers className="w-4 h-4" />
          Choose New File
        </button>
        <div className="flex items-center gap-2">
          <span className="text-sm font-bold text-slate-700">
            {currentIndex + 1} / {cards.length}
          </span>
        </div>
        <button 
          onClick={handleShuffle}
          className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-all"
          title="Shuffle Deck"
        >
          <Shuffle className="w-4 h-4" />
        </button>
      </div>

      {/* Progress Bar */}
      <div className="w-full h-1.5 bg-slate-200 rounded-full mb-8 overflow-hidden">
        <div 
          className="h-full bg-gradient-to-r from-indigo-500 to-purple-500 transition-all duration-300 ease-out"
          style={{ width: `${progress}%` }}
        ></div>
      </div>

      {/* Card Container */}
      <div className="flex-1 flex flex-col justify-center perspective-1000 relative">
        <div 
          className="relative w-full aspect-[4/3] cursor-pointer group"
          onClick={handleFlip}
        >
          <div 
            className={`
              w-full h-full relative transform-style-3d transition-transform duration-500 ease-in-out shadow-2xl rounded-3xl
              ${isFlipped ? 'rotate-y-180' : ''}
            `}
          >
            {/* Front of Card (Question) */}
            <div className="absolute w-full h-full backface-hidden bg-white rounded-3xl p-8 md:p-12 flex flex-col items-center justify-center text-center border border-slate-100">
              <span className="absolute top-6 left-6 text-xs font-bold tracking-wider text-indigo-500 uppercase">
                Question
              </span>
              {currentCard.category && (
                <span className="absolute top-6 right-6 text-xs font-medium text-slate-400 bg-slate-100 px-3 py-1 rounded-full">
                  {currentCard.category}
                </span>
              )}
              <h3 className="text-xl md:text-3xl font-bold text-slate-800 leading-relaxed">
                {currentCard.question}
              </h3>
              <p className="absolute bottom-8 text-sm text-slate-400 font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                Tap to flip
              </p>
            </div>

            {/* Back of Card (Answer) */}
            <div className="absolute w-full h-full backface-hidden rotate-y-180 bg-gradient-to-br from-indigo-600 to-purple-700 rounded-3xl p-8 md:p-12 flex flex-col items-center justify-center text-center text-white">
              <span className="absolute top-6 left-6 text-xs font-bold tracking-wider text-white/70 uppercase">
                Answer
              </span>
              <p className="text-lg md:text-2xl font-medium leading-relaxed">
                {currentCard.answer}
              </p>
            </div>
          </div>
        </div>
      </div>

      {/* Navigation Controls */}
      <div className="mt-8 flex items-center justify-center gap-6">
        <button
          onClick={handlePrev}
          disabled={currentIndex === 0}
          className={`
            p-4 rounded-full border-2 transition-all duration-200
            ${currentIndex === 0 
              ? 'border-slate-200 text-slate-300 cursor-not-allowed' 
              : 'border-slate-200 text-slate-600 hover:border-indigo-500 hover:text-indigo-600 hover:scale-105 bg-white'
            }
          `}
        >
          <ChevronLeft className="w-6 h-6" />
        </button>

        <button
          onClick={() => {
            setCurrentIndex(0);
            setIsFlipped(false);
          }}
          className="p-4 rounded-full border-2 border-slate-200 text-slate-400 hover:border-slate-400 hover:text-slate-600 transition-all bg-white"
          title="Restart"
        >
          <RotateCcw className="w-5 h-5" />
        </button>

        <button
          onClick={handleNext}
          disabled={currentIndex === cards.length - 1}
          className={`
            p-4 rounded-full border-2 transition-all duration-200
            ${currentIndex === cards.length - 1
              ? 'border-slate-200 text-slate-300 cursor-not-allowed' 
              : 'border-slate-200 text-slate-600 hover:border-indigo-500 hover:text-indigo-600 hover:scale-105 bg-white'
            }
          `}
        >
          <ChevronRight className="w-6 h-6" />
        </button>
      </div>
    </div>
  );
};

export default FlashcardDeck;

import React, { useState } from 'react';
import { Brain, Sparkles, Github } from 'lucide-react';
import FileUpload from './components/FileUpload';
import FlashcardDeck from './components/FlashcardDeck';
import { AppState, FlashcardData } from './types';
import { generateFlashcardsFromPdf } from './services/geminiService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [flashcards, setFlashcards] = useState<FlashcardData[]>([]);
  const [error, setError] = useState<string | null>(null);

  const handleFileSelect = async (file: File) => {
    setAppState(AppState.PROCESSING);
    setError(null);

    const reader = new FileReader();
    reader.onload = async () => {
      try {
        const base64String = reader.result as string;
        // Strip the data URL prefix to get just the base64 data
        const base64Data = base64String.split(',')[1];

        const generatedCards = await generateFlashcardsFromPdf(base64Data);

        if (generatedCards.length === 0) {
            throw new Error("Could not generate any flashcards. The PDF might be empty or unreadable.");
        }

        setFlashcards(generatedCards);
        setAppState(AppState.STUDYING);
      } catch (err) {
        setAppState(AppState.ERROR);
        setError(err instanceof Error ? err.message : "An unexpected error occurred processing your file.");
      }
    };

    reader.onerror = () => {
      setAppState(AppState.ERROR);
      setError("Failed to read the file.");
    };

    reader.readAsDataURL(file);
  };

  const handleReset = () => {
    setAppState(AppState.IDLE);
    setFlashcards([]);
    setError(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Navbar */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={handleReset}>
            <div className="bg-indigo-600 p-1.5 rounded-lg">
              <Brain className="w-6 h-6 text-white" />
            </div>
            <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
              FlashMind
            </span>
          </div>
          <div className="flex items-center gap-4">
             <span className="hidden sm:inline-block text-xs font-medium px-2 py-1 bg-indigo-50 text-indigo-700 rounded-md border border-indigo-100">
                Powered by Gemini 2.5
             </span>
             <a href="#" className="text-slate-400 hover:text-slate-600 transition-colors">
               <Github className="w-5 h-5" />
             </a>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 flex flex-col">
        <div className="max-w-5xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 md:py-12 flex-1 flex flex-col">

          {appState === AppState.IDLE || appState === AppState.PROCESSING || appState === AppState.ERROR ? (
             <div className="flex-1 flex flex-col items-center justify-center min-h-[500px] animate-in fade-in duration-500">
                <div className="text-center mb-12 max-w-2xl">
                  <h1 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight mb-4">
                    Turn any PDF into <br/>
                    <span className="text-indigo-600">Smart Flashcards</span>
                  </h1>
                  <p className="text-lg text-slate-500">
                    Upload your lecture notes, textbooks, or research papers. 
                    FlashMind uses AI to extract key concepts and generate interactive study aids instantly.
                  </p>
                </div>

                <div className="w-full">
                  <FileUpload 
                    onFileSelect={handleFileSelect} 
                    isLoading={appState === AppState.PROCESSING}
                    error={error}
                  />
                </div>

                {/* Features Grid */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-16 text-left w-full max-w-4xl">
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                      <div className="w-10 h-10 bg-blue-50 rounded-lg flex items-center justify-center mb-4">
                        <Sparkles className="w-5 h-5 text-blue-600" />
                      </div>
                      <h3 className="font-semibold text-slate-900 mb-2">Instant Generation</h3>
                      <p className="text-sm text-slate-500">Just drop your file and wait a few seconds. No manual typing required.</p>
                   </div>
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                      <div className="w-10 h-10 bg-purple-50 rounded-lg flex items-center justify-center mb-4">
                        <Brain className="w-5 h-5 text-purple-600" />
                      </div>
                      <h3 className="font-semibold text-slate-900 mb-2">Smart Context</h3>
                      <p className="text-sm text-slate-500">AI understands the context of your document to create meaningful questions.</p>
                   </div>
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                      <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center mb-4">
                        <Layers className="w-5 h-5 text-indigo-600" />
                      </div>
                      <h3 className="font-semibold text-slate-900 mb-2">Study Mode</h3>
                      <p className="text-sm text-slate-500">Distraction-free interface designed to help you memorize effectively.</p>
                   </div>
                </div>
             </div>
          ) : (
            <div className="flex-1 animate-in slide-in-from-bottom-8 duration-700 fade-in">
              <FlashcardDeck cards={flashcards} onReset={handleReset} />
            </div>
          )}
        </div>
      </main>

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-6">
        <div className="max-w-5xl mx-auto px-4 text-center text-sm text-slate-500">
          <p>© {new Date().getFullYear()} FlashMind PDF. Built with Gemini API & React.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

