import { GoogleGenAI, Type } from "@google/genai";
import { FlashcardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateFlashcardsFromPdfs = async (
  base64Pdfs: string[],
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question for the flashcard. Be concise but specific. Use LaTeX for math."
          },
          answer: {
            type: Type.STRING,
            description: "The answer to the question. Accurate and easy to memorize. Use LaTeX for math."
          },
          category: {
            type: Type.STRING,
            description: "A short tag or category for this card (e.g., 'Definitions', 'Dates', 'Concepts')."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached PDF documents. 
      Create a set of comprehensive flashcards (at least 15, up to 30) based on the combined key concepts, definitions, and important details found in all the texts.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}

      Instructions:
      1. Ensure the questions are clear and the answers are accurate.
      2. If the content involves mathematics, physics, or chemistry, YOU MUST use standard LaTeX syntax for equations and formulas (e.g., $E=mc^2$, $\\frac{a}{b}$).
      3. Do not wrap the entire output in a markdown block, just return the JSON.
      4. Synthesize information from multiple documents if they cover related topics.
    `;

    // Construct the parts array with all PDFs
    const contentParts = base64Pdfs.map(base64Data => ({
      inlineData: {
        data: base64Data,
        mimeType: "application/pdf",
      },
    }));

    // Add the text prompt at the end
    contentParts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: contentParts,
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    const parsedData = JSON.parse(jsonText);

    // Add IDs to the cards for React keys
    return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
      ...card,
      id: `card-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

