import { Deck } from "../types";

const STORAGE_KEY = 'flashmind_decks';

export const getDecks = (): Deck[] => {
  try {
    const data = localStorage.getItem(STORAGE_KEY);
    return data ? JSON.parse(data) : [];
  } catch (e) {
    console.error("Failed to load decks", e);
    return [];
  }
};

export const saveDeck = (deck: Deck): void => {
  try {
    const decks = getDecks();
    const index = decks.findIndex(d => d.id === deck.id);

    if (index >= 0) {
      // Update existing
      decks[index] = deck;
    } else {
      // Add new
      decks.unshift(deck); // Add to top
    }

    localStorage.setItem(STORAGE_KEY, JSON.stringify(decks));
  } catch (e) {
    console.error("Failed to save deck", e);
    throw new Error("Could not save to local storage. It might be full.");
  }
};

export const deleteDeck = (id: string): void => {
  const decks = getDecks().filter(d => d.id !== id);
  localStorage.setItem(STORAGE_KEY, JSON.stringify(decks));
};

