    </div>
  );
};

export default Library;

export interface FlashcardData {
  id: string;
  question: string;
  answer: string;
  category?: string;
}

export interface Deck {
  id: string;
  title: string;
  createdAt: number;
  cards: FlashcardData[];
  categoryId?: string;
}

export interface Category {
  id: string;
  name: string;
}

export enum AppState {
  IDLE = 'IDLE',
  PROCESSING = 'PROCESSING',
  STUDYING = 'STUDYING',
  LIBRARY = 'LIBRARY',
  ERROR = 'ERROR'
}

export interface ProcessingStatus {
  step: string;
  progress: number;
}

import { Deck, Category } from "../types";

const DECKS_KEY = 'flashmind_decks';
const CATEGORIES_KEY = 'flashmind_categories';

export const getDecks = (): Deck[] => {
  try {
    const data = localStorage.getItem(DECKS_KEY);
    if (!data) return [];

    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    console.error("Failed to load decks from local storage", e);
    return [];
  }
};

export const saveDeck = (deck: Deck): void => {
  try {
    const decks = getDecks();
    const index = decks.findIndex(d => d.id === deck.id);

    if (index >= 0) {
      decks[index] = deck;
    } else {
      decks.unshift(deck);
    }

    localStorage.setItem(DECKS_KEY, JSON.stringify(decks));
  } catch (e) {
    console.error("Failed to save deck", e);
    throw new Error("Could not save to local storage. Storage might be full.");
  }
};

export const deleteDeck = (id: string): void => {
  try {
    const decks = getDecks().filter(d => d.id !== id);
    localStorage.setItem(DECKS_KEY, JSON.stringify(decks));
  } catch (e) {
     console.error("Failed to delete deck", e);
  }
};

// Category Methods

export const getCategories = (): Category[] => {
  try {
    const data = localStorage.getItem(CATEGORIES_KEY);
    if (!data) return [];
    const parsed = JSON.parse(data);
    return Array.isArray(parsed) ? parsed : [];
  } catch (e) {
    console.error("Failed to load categories", e);
    return [];
  }
};

export const saveCategory = (category: Category): void => {
  try {
    const categories = getCategories();
    // Check for duplicates by ID
    const index = categories.findIndex(c => c.id === category.id);
    if (index >= 0) {
      categories[index] = category;
    } else {
      categories.push(category);
    }
    localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));
  } catch (e) {
    console.error("Failed to save category", e);
  }
};

export const deleteCategory = (id: string): void => {
  try {
    const categories = getCategories().filter(c => c.id !== id);
    localStorage.setItem(CATEGORIES_KEY, JSON.stringify(categories));

    // Also remove this category from any decks using it
    const decks = getDecks();
    let decksChanged = false;
    const updatedDecks = decks.map(deck => {
      if (deck.categoryId === id) {
        decksChanged = true;
        return { ...deck, categoryId: undefined };
      }
      return deck;
    });

    if (decksChanged) {
      localStorage.setItem(DECKS_KEY, JSON.stringify(updatedDecks));
    }
  } catch (e) {
    console.error("Failed to delete category", e);
  }
};

import React, { useState, useEffect } from 'react';
import { Brain, Sparkles, Github, Layers, BookOpen, CheckCircle, AlertCircle, X, Trash2, Edit2, Plus, Folder } from 'lucide-react';
import FileUpload from './components/FileUpload';
import FlashcardDeck from './components/FlashcardDeck';
import Library from './components/Library';
import { AppState, Deck, FlashcardData, Category } from './types';
import { generateFlashcardsFromPdfs } from './services/geminiService';
import { saveDeck, getDecks, deleteDeck, getCategories, saveCategory, deleteCategory } from './services/storageService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [currentDeck, setCurrentDeck] = useState<Deck | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDecks, setSavedDecks] = useState<Deck[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);

  // UI State for Modals and Toasts
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showEditDeckModal, setShowEditDeckModal] = useState(false);

  const [deckToDelete, setDeckToDelete] = useState<string | null>(null);
  const [deckToEdit, setDeckToEdit] = useState<Deck | null>(null);

  const [saveName, setSaveName] = useState('');
  const [saveCategoryId, setSaveCategoryId] = useState<string>('');

  const [newCategoryName, setNewCategoryName] = useState('');

  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Load data on mount
  useEffect(() => {
    refreshData();
  }, []);

  // Auto-dismiss toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const refreshData = () => {
    setSavedDecks(getDecks());
    setCategories(getCategories());
  };

  const handleFilesSelect = async (files: File[]) => {
    setAppState(AppState.PROCESSING);
    setError(null);

    try {
      // Check for JSON deck
      const jsonFile = files.find(f => f.name.endsWith('.json') || f.type === 'application/json');

      if (jsonFile) {
        const text = await jsonFile.text();
        const savedCards = JSON.parse(text) as FlashcardData[];
        if (!Array.isArray(savedCards) || savedCards.length === 0 || !savedCards[0].question) {
           throw new Error("Invalid flashcard deck file.");
        }

        // Create a temporary deck wrapper
        const deck: Deck = {
            id: `imported-${Date.now()}`,
            title: jsonFile.name.replace('.json', ''),
            createdAt: Date.now(),
            cards: savedCards
        };

        setCurrentDeck(deck);
        setAppState(AppState.STUDYING);
        return;
      }

      // Process PDFs
      const pdfFiles = files.filter(f => f.name.endsWith('.pdf') || f.type === 'application/pdf');
      if (pdfFiles.length === 0) throw new Error("No PDF files selected.");

      const fileReadPromises = pdfFiles.map(file => new Promise<string>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
           const base64String = reader.result as string;
           const base64Data = base64String.split(',')[1];
           resolve(base64Data);
        };
        reader.onerror = () => reject(new Error(`Failed to read file: ${file.name}`));
        reader.readAsDataURL(file);
      }));

      const base64Pdfs = await Promise.all(fileReadPromises);
      const generatedCards = await generateFlashcardsFromPdfs(base64Pdfs);

      if (generatedCards.length === 0) {
          throw new Error("Could not generate any flashcards.");
      }

      const defaultTitle = pdfFiles.length === 1 
          ? pdfFiles[0].name.replace('.pdf', '') 
          : `Study Session ${new Date().toLocaleDateString()}`;

      const newDeck: Deck = {
          id: `deck-${Date.now()}`,
          title: defaultTitle,
          createdAt: Date.now(),
          cards: generatedCards
      };

      setCurrentDeck(newDeck);
      setAppState(AppState.STUDYING);

    } catch (err) {
      setAppState(AppState.ERROR);
      setError(err instanceof Error ? err.message : "An error occurred.");
    }
  };

  const handleSaveToLibrary = () => {
    if (!currentDeck) return;

    const exists = savedDecks.some(d => d.id === currentDeck.id);
    if (exists) {
        setToast({ message: 'This deck is already saved to your library.', type: 'error' });
        return;
    }

    setSaveName(currentDeck.title);
    setSaveCategoryId('');
    setShowSaveModal(true);
  };

  const confirmSaveDeck = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!currentDeck) return;

    const finalTitle = saveName.trim() || currentDeck.title;

    try {
      const deckToSave = { 
        ...currentDeck, 
        title: finalTitle,
        categoryId: saveCategoryId || undefined
      };
      saveDeck(deckToSave);

      setCurrentDeck(deckToSave);
      refreshData();

      setShowSaveModal(false);
      setToast({ message: 'Deck saved successfully!', type: 'success' });
