          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             <button 
                onClick={handleGoToLibrary}
                className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-colors
                  ${appState === AppState.LIBRARY 
