import React, { useState, useRef } from 'react';
import { Upload, FileText, Loader2, AlertCircle, X, Plus, Layers, FileJson, Image as ImageIcon } from 'lucide-react';

interface FileUploadProps {
  onFilesSelect: (files: File[]) => void;
  isLoading: boolean;
  error?: string | null;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFilesSelect, isLoading, error }) => {
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    if (!isLoading) setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (isLoading) return;

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      addFiles(Array.from(e.target.files));
    }
    // Reset input to allow selecting the same file again if needed
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const addFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => 
      file.type === 'application/pdf' || 
      file.type === 'application/json' ||
      file.type.startsWith('image/') ||
      file.name.endsWith('.pdf') || 
      file.name.endsWith('.json') ||
      /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(file.name)
    );

    if (validFiles.length === 0 && newFiles.length > 0) {
      alert('Please upload valid PDF files, Images, or a JSON flashcard deck.');
      return;
    }

    // Filter out duplicates based on name and size
    const uniqueFiles = validFiles.filter(newFile => 
      !selectedFiles.some(existing => 
        existing.name === newFile.name && existing.size === newFile.size
      )
    );

    setSelectedFiles(prev => [...prev, ...uniqueFiles]);
  };

  const removeFile = (indexToRemove: number) => {
    setSelectedFiles(prev => prev.filter((_, index) => index !== indexToRemove));
  };

  const handleGenerate = () => {
    if (selectedFiles.length > 0) {
      onFilesSelect(selectedFiles);
    }
  };

  const triggerFileInput = () => {
    if (!isLoading) fileInputRef.current?.click();
  };

  const isJsonDeck = selectedFiles.some(f => f.name.endsWith('.json'));

  const getFileIcon = (file: File) => {
    if (file.name.endsWith('.json')) return <FileJson className="w-4 h-4" />;
    if (file.type.startsWith('image/') || /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(file.name)) return <ImageIcon className="w-4 h-4" />;
    return <FileText className="w-4 h-4" />;
  };

  const getFileColorClass = (file: File) => {
    if (file.name.endsWith('.json')) return 'bg-yellow-50 text-yellow-500';
    if (file.type.startsWith('image/') || /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(file.name)) return 'bg-purple-50 text-purple-500';
    return 'bg-red-50 text-red-500';
  };

  return (
    <div className="w-full max-w-xl mx-auto space-y-6">
      {/* Drop Zone */}
      <div
        className={`relative border-2 border-dashed rounded-2xl p-8 transition-all duration-300 ease-in-out text-center cursor-pointer overflow-hidden
          ${isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.02]' 
            : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50 bg-white'
          }
          ${isLoading ? 'opacity-50 pointer-events-none' : ''}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={triggerFileInput}
      >
        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept=".pdf,.json,.jpg,.jpeg,.png,.webp,.heic,.heif,application/pdf,application/json,image/*"
          multiple
          onChange={handleFileInput}
        />

        <div className="flex flex-col items-center justify-center space-y-4">
          <div className={`p-4 rounded-full ${isDragging ? 'bg-indigo-100' : 'bg-slate-100'}`}>
            {isLoading ? (
              <Loader2 className="w-8 h-8 text-indigo-600 animate-spin" />
            ) : (
              <Upload className={`w-8 h-8 ${isDragging ? 'text-indigo-600' : 'text-slate-400'}`} />
            )}
          </div>

          <div className="space-y-2">
            <h3 className="text-lg font-semibold text-slate-700">
              {isLoading ? 'Processing Documents...' : 'Upload PDFs, Images, or Deck'}
            </h3>
            <p className="text-sm text-slate-500 max-w-xs mx-auto">
              {isLoading 
                ? 'Gemini is analyzing your files and creating flashcards.' 
                : 'Drag and drop PDF files, Images, or a saved JSON deck here.'}
            </p>
          </div>
        </div>
      </div>

      {/* Selected Files List */}
      {selectedFiles.length > 0 && (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-bottom-2">
          <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
              Selected Files ({selectedFiles.length})
            </h4>
            <button 
               onClick={triggerFileInput}
               className="text-indigo-600 hover:text-indigo-700 text-xs font-medium flex items-center gap-1"
               disabled={isLoading}
            >
              <Plus className="w-3 h-3" /> Add more
            </button>
          </div>
          <ul className="divide-y divide-slate-100">
            {selectedFiles.map((file, index) => (
              <li key={`${file.name}-${index}`} className="px-4 py-3 flex items-center justify-between group hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3 overflow-hidden">
                  <div className={`p-2 rounded-lg shrink-0 ${getFileColorClass(file)}`}>
                    {getFileIcon(file)}
                  </div>
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-slate-700 truncate">{file.name}</p>
                    <p className="text-xs text-slate-400">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                  </div>
                </div>
                {!isLoading && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); removeFile(index); }}
                    className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-full transition-all"
                    title="Remove file"
                  >
                    <X className="w-4 h-4" />
                  </button>
                )}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Generate Button */}
      {selectedFiles.length > 0 && !isLoading && (
        <button
          onClick={handleGenerate}
          className={`w-full py-4 bg-gradient-to-r text-white rounded-xl font-bold shadow-lg transition-all active:scale-[0.99] flex items-center justify-center gap-2
             ${isJsonDeck 
               ? 'from-emerald-500 to-teal-500 shadow-emerald-200 hover:shadow-xl' 
               : 'from-indigo-600 to-purple-600 shadow-indigo-200 hover:shadow-xl hover:scale-[1.01]'
             }
          `}
        >
          {isJsonDeck ? (
             <>
               <FileJson className="w-5 h-5" />
               Load Saved Deck
             </>
          ) : (
             <>
               <Layers className="w-5 h-5" />
               Generate Flashcards
             </>
          )}
        </button>
      )}

      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-xl flex items-start gap-3 text-red-700 animate-in fade-in slide-in-from-bottom-2">
          <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <p className="text-sm">{error}</p>
        </div>
      )}
    </div>
  );
};

export default FileUpload;

import React, { useState, useEffect } from 'react';
import { Brain, Sparkles, Github, Layers, BookOpen, CheckCircle, AlertCircle, X, Trash2, Edit2, Plus, Folder } from 'lucide-react';
import FileUpload from './components/FileUpload';
import FlashcardDeck from './components/FlashcardDeck';
import Library from './components/Library';
import { AppState, Deck, FlashcardData, Category } from './types';
import { generateFlashcardsFromContent } from './services/geminiService';
import { saveDeck, getDecks, deleteDeck, getCategories, saveCategory, deleteCategory } from './services/storageService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [currentDeck, setCurrentDeck] = useState<Deck | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDecks, setSavedDecks] = useState<Deck[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);

  // UI State for Modals and Toasts
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showEditDeckModal, setShowEditDeckModal] = useState(false);

  const [deckToDelete, setDeckToDelete] = useState<string | null>(null);
  const [deckToEdit, setDeckToEdit] = useState<Deck | null>(null);

  const [saveName, setSaveName] = useState('');
  const [saveCategoryId, setSaveCategoryId] = useState<string>('');

  const [newCategoryName, setNewCategoryName] = useState('');

  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Load data on mount
  useEffect(() => {
    refreshData();
  }, []);

  // Auto-dismiss toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const refreshData = () => {
    setSavedDecks(getDecks());
    setCategories(getCategories());
  };

  const handleFilesSelect = async (files: File[]) => {
    setAppState(AppState.PROCESSING);
    setError(null);

    try {
      // Check for JSON deck
      const jsonFile = files.find(f => f.name.endsWith('.json') || f.type === 'application/json');

      if (jsonFile) {
        const text = await jsonFile.text();
        const savedCards = JSON.parse(text) as FlashcardData[];
        if (!Array.isArray(savedCards) || savedCards.length === 0 || !savedCards[0].question) {
           throw new Error("Invalid flashcard deck file.");
        }

        // Create a temporary deck wrapper
        const deck: Deck = {
            id: `imported-${Date.now()}`,
            title: jsonFile.name.replace('.json', ''),
            createdAt: Date.now(),
            cards: savedCards
        };

        setCurrentDeck(deck);
        setAppState(AppState.STUDYING);
        return;
      }

      // Process PDFs and Images
      const contentFiles = files.filter(f => 
        f.type === 'application/pdf' || 
        f.name.endsWith('.pdf') ||
        f.type.startsWith('image/') ||
        /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(f.name)
      );

      if (contentFiles.length === 0) throw new Error("No supported files (PDF or Images) selected.");

      const fileReadPromises = contentFiles.map(file => new Promise<{ mimeType: string; data: string }>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
           const base64String = reader.result as string;
           const base64Data = base64String.split(',')[1];
           // Ensure mimeType is valid. If file.type is empty (sometimes happens), try to guess or default
           let mimeType = file.type;
           if (!mimeType) {
             if (file.name.endsWith('.pdf')) mimeType = 'application/pdf';
             else if (file.name.match(/\.(jpg|jpeg)$/i)) mimeType = 'image/jpeg';
             else if (file.name.match(/\.png$/i)) mimeType = 'image/png';
             else if (file.name.match(/\.webp$/i)) mimeType = 'image/webp';
             else if (file.name.match(/\.heic$/i)) mimeType = 'image/heic';
             else mimeType = 'application/octet-stream';
           }
           resolve({ mimeType, data: base64Data });
        };
        reader.onerror = () => reject(new Error(`Failed to read file: ${file.name}`));
        reader.readAsDataURL(file);
      }));

      const fileData = await Promise.all(fileReadPromises);
      const generatedCards = await generateFlashcardsFromContent(fileData);

      if (generatedCards.length === 0) {
          throw new Error("Could not generate any flashcards.");
      }

      const defaultTitle = contentFiles.length === 1 
          ? contentFiles[0].name.replace(/\.[^/.]+$/, "") 
          : `Study Session ${new Date().toLocaleDateString()}`;

      const newDeck: Deck = {
          id: `deck-${Date.now()}`,
          title: defaultTitle,
          createdAt: Date.now(),
          cards: generatedCards
      };

      setCurrentDeck(newDeck);
      setAppState(AppState.STUDYING);

    } catch (err) {
      setAppState(AppState.ERROR);
      setError(err instanceof Error ? err.message : "An error occurred.");
    }
  };

  const handleSaveToLibrary = () => {
    if (!currentDeck) return;

    const exists = savedDecks.some(d => d.id === currentDeck.id);
    if (exists) {
        setToast({ message: 'This deck is already saved to your library.', type: 'error' });
        return;
    }

    setSaveName(currentDeck.title);
    setSaveCategoryId('');
    setShowSaveModal(true);
  };

  const confirmSaveDeck = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!currentDeck) return;

    const finalTitle = saveName.trim() || currentDeck.title;

