import React, { useState, useEffect } from 'react';
import { RotateCcw, Shuffle, Layers, Check, X, Repeat, Trophy, Download, Bookmark, BookmarkCheck, FileSpreadsheet, FileJson } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import { FlashcardData } from '../types';

interface FlashcardDeckProps {
  cards: FlashcardData[];
  deckTitle?: string;
  isSaved?: boolean;
  onReset: () => void;
  onSaveToLibrary: () => void;
}

const FlashcardDeck: React.FC<FlashcardDeckProps> = ({ 
  cards: initialCards, 
  deckTitle, 
  isSaved = false, 
  onReset, 
  onSaveToLibrary 
}) => {
  // We manage a queue of cards to study
  const [queue, setQueue] = useState<FlashcardData[]>(initialCards);
  const [completedCount, setCompletedCount] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [totalCards] = useState(initialCards.length);

  // When the queue changes (new card), ensure it starts face up (question side)
  useEffect(() => {
    setIsFlipped(false);
  }, [queue]);

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
