const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateFlashcardsFromContent = async (
  files: { mimeType: string; data: string }[],
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question for the flashcard. Be concise but specific. Use LaTeX for math."
          },
          answer: {
            type: Type.STRING,
            description: "The answer to the question. Accurate and easy to memorize. Use LaTeX for math."
          },
          category: {
            type: Type.STRING,
            description: "A short tag or category for this card (e.g., 'Definitions', 'Dates', 'Concepts')."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached documents (PDFs) and images deeply. 
      Create a very comprehensive and exhaustive set of flashcards based STRICTLY and ONLY on the content found in the uploaded files.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}

      Instructions:
      1. STRICT ADHERENCE TO SOURCE: Use ONLY the information provided in the documents. Do NOT add external facts, general knowledge, or information not explicitly present in the text or images. If the document does not mention it, do not include it.
      2. GENERATE AS MANY FLASHCARDS AS POSSIBLE to fully cover the material provided. Aim for 50 to 100 cards if the content supports it.
      3. Ensure the questions are clear and the answers are derived directly from the source text.
      4. MATHEMATICS AND CHEMISTRY FORMATTING:
         - When writing math, wrap any math with the \\( ... \\) tags [eg, \\( a^2+b^2=c^2 \\) ]. By default this is inline math. For block math, use \\[ ... \\]. Decide when formatting each card.
         - When writing chemistry equations, use the format \\( \\ce{C6H12O6 + 6O2 -> 6H2O + 6CO2} \\) where the \\ce is required for MathJax chemistry.
      5. Break down complex topics into multiple atomic flashcards.
      6. Do not wrap the entire output in a markdown block, just return the JSON.
      7. STRICTLY GENERATE THE FLASHCARDS IN THE SAME LANGUAGE AS THE SOURCE TEXT. If the content is in Spanish, the questions and answers MUST be in Spanish.
    `;

    // Construct the parts array
    const contentParts = files.map(file => ({
      inlineData: {
        data: file.data,
        mimeType: file.mimeType || "application/pdf", 
      },
    }));

    // Add the text prompt at the end
    contentParts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: contentParts,
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        maxOutputTokens: 8192, // Allow for a large number of cards
      },
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    const parsedData = JSON.parse(jsonText);

    // Add IDs to the cards for React keys
    return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
      ...card,
      id: `card-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
