const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateFlashcardsFromContent = async (
  files: { mimeType: string; data: string }[],
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          answer: {
            type: Type.STRING,
            description: "The answer. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          category: {
            type: Type.STRING,
            description: "Category tag."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached documents (PDFs) and images deeply. 
      Create a comprehensive set of flashcards based STRICTLY on the content found in the uploaded files.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}

      Instructions:
      1. STRICT ADHERENCE TO SOURCE: Use ONLY the information provided in the documents.
      2. CARD COUNT: Generate 30 to 50 high-quality flashcards. Do not generate too few, but ensure they fit within the output limit.
      3. FORMATTING (CRITICAL):
         - You are outputting a raw JSON string. 
         - **DOUBLE ESCAPE ALL BACKSLASHES** used in LaTeX. 
         - To write a LaTeX start tag like \\( , you MUST write "\\\\(" in the JSON string.
         - To write a LaTeX end tag like \\) , you MUST write "\\\\)" in the JSON string.
         - Example: "question": "Solve for \\\\( x \\\\) in \\\\( x^2 = 4 \\\\)"
         - For Chemistry \\ce{}, write "\\\\ce{...}".
         - Escape all double quotes inside strings (e.g. \\").
      4. Break down complex topics into multiple atomic flashcards.
      5. STRICTLY GENERATE THE FLASHCARDS IN THE SAME LANGUAGE AS THE SOURCE TEXT.
      6. Do not include markdown formatting (like \`\`\`json) in the response text, just the raw JSON.
    `;

    // Construct the parts array
    const contentParts = files.map(file => ({
      inlineData: {
        data: file.data,
        mimeType: file.mimeType || "application/pdf", 
      },
    }));

    // Add the text prompt at the end
    contentParts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: contentParts,
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        maxOutputTokens: 8192, 
      },
    });

    let jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    // Clean up potential markdown formatting if the model disregards instructions
    if (jsonText.startsWith("```json")) {
      jsonText = jsonText.replace(/^```json\s*/, "").replace(/\s*```$/, "");
    } else if (jsonText.startsWith("```")) {
      jsonText = jsonText.replace(/^```\s*/, "").replace(/\s*```$/, "");
    }

    // Attempt to parse
    try {
      const parsedData = JSON.parse(jsonText);

      // Add IDs to the cards for React keys
      return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
        ...card,
        id: `card-${Date.now()}-${index}`
      }));
    } catch (parseError) {
      console.error("JSON Parse Error. Raw text snippet:", jsonText.substring(0, 200) + "...");
      console.error(parseError);
      throw new Error("Failed to process the AI response. The generated content was not valid JSON.");
    }

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { FlashcardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean JSON string with regex
const cleanJsonString = (str: string): string => {
  // Remove markdown code blocks if present
  let cleaned = str.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  // Replace unescaped backslashes that are likely part of LaTeX
  // We want to find a backslash \ that is NOT:
  // 1. Preceded by another backslash (avoid escaping \\)
  // 2. Followed by a valid JSON escape character (", \, /, b, f, n, r, t, u)
  // And replace it with \\
  // This handles cases where the model outputs "\omega" (invalid) instead of "\\omega" (valid)
  return cleaned.replace(/(?<!\\)\\(?!["\\/bfnrtu])/g, "\\\\");
};

export const generateFlashcardsFromContent = async (
  files: { mimeType: string; data: string }[],
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          answer: {
            type: Type.STRING,
            description: "The answer. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          category: {
            type: Type.STRING,
            description: "Category tag."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached documents (PDFs) and images deeply. 
      Create a comprehensive set of flashcards based STRICTLY on the content found in the uploaded files.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}

      Instructions:
      1. STRICT ADHERENCE TO SOURCE: Use ONLY the information provided in the documents.
      2. CARD COUNT: Generate 20 to 40 high-quality flashcards. Prioritize accuracy and valid formatting over quantity.
      3. FORMATTING (CRITICAL):
         - You are outputting a raw JSON string. 
         - **DOUBLE ESCAPE ALL BACKSLASHES** used in LaTeX. 
         - To write a LaTeX start tag like \\( , you MUST write "\\\\(" in the JSON string.
         - To write a LaTeX end tag like \\) , you MUST write "\\\\)" in the JSON string.
         - Example: "question": "Solve for \\\\( x \\\\) in \\\\( x^2 = 4 \\\\)"
         - For Chemistry \\ce{}, write "\\\\ce{...}".
         - Escape all double quotes inside strings (e.g. \\").
         - DO NOT use real line breaks inside strings. Use \\n for line breaks.
      4. Break down complex topics into multiple atomic flashcards.
      5. STRICTLY GENERATE THE FLASHCARDS IN THE SAME LANGUAGE AS THE SOURCE TEXT.
      6. Output pure JSON.
    `;

    // Construct the parts array
    const contentParts = files.map(file => ({
      inlineData: {
        data: file.data,
        mimeType: file.mimeType || "application/pdf", 
      },
    }));

    // Add the text prompt at the end
    contentParts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: contentParts,
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        maxOutputTokens: 8192, 
      },
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    let parsedData: any[] = [];

    try {
        // 1. Try parsing the response directly (after basic markdown cleanup)
        const simpleClean = jsonText.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");
        parsedData = JSON.parse(simpleClean);
    } catch (e1) {
        console.warn("Direct JSON parse failed, attempting regex cleanup...", e1);
        try {
            // 2. Try aggressive backslash cleaning for LaTeX
            const aggressiveClean = cleanJsonString(jsonText);
            parsedData = JSON.parse(aggressiveClean);
        } catch (e2) {
            console.warn("Cleanup parse failed, checking for truncation...", e2);
            // 3. Last resort: Try to salvage truncated JSON
             // If the response was truncated (max tokens), it might end abruptly.
             // We look for the last closed object "}," and close the array.
             // Regex to find the last valid object closing
             const lastObjectEnd = jsonText.lastIndexOf("},");

             if (lastObjectEnd !== -1) {
                 // Take everything up to the last "}," (inclusive), then add "]"
                 const salvaged = jsonText.substring(0, lastObjectEnd + 1) + "]";

                 try {
                      // We also need to clean the salvaged string
                      const cleanedSalvaged = cleanJsonString(salvaged);
                      parsedData = JSON.parse(cleanedSalvaged);
                 } catch (e3) {
                     console.error("Salvage failed:", e3);
                     // Provide the raw text for debugging in console but throw user error
                     throw new Error("Failed to process the AI response. The generated content was not valid JSON.");
                 }
             } else {
                 throw new Error("Failed to process the AI response. The generated content was not valid JSON.");
             }
        }
    }

    // Add IDs to the cards for React keys
    return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
      ...card,
      id: `card-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Brain, Sparkles, Github, Layers, BookOpen, CheckCircle, AlertCircle, X, Trash2, Edit2, Plus, Folder } from 'lucide-react';
import FileUpload from './components/FileUpload';
import FlashcardDeck from './components/FlashcardDeck';
import Library from './components/Library';
import { AppState, Deck, FlashcardData, Category } from './types';
import { generateFlashcardsFromContent } from './services/geminiService';
import { saveDeck, getDecks, deleteDeck, getCategories, saveCategory, deleteCategory } from './services/storageService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [currentDeck, setCurrentDeck] = useState<Deck | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDecks, setSavedDecks] = useState<Deck[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);

  // Store the raw file data to allow regeneration
  const [lastUploadedAssets, setLastUploadedAssets] = useState<{ mimeType: string; data: string }[] | null>(null);

  // UI State for Modals and Toasts
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showEditDeckModal, setShowEditDeckModal] = useState(false);

  const [deckToDelete, setDeckToDelete] = useState<string | null>(null);
  const [deckToEdit, setDeckToEdit] = useState<Deck | null>(null);

  const [saveName, setSaveName] = useState('');
  const [saveCategoryId, setSaveCategoryId] = useState<string>('');

  const [newCategoryName, setNewCategoryName] = useState('');

  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Load data on mount
  useEffect(() => {
    refreshData();
  }, []);

  // Auto-dismiss toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const refreshData = () => {
    setSavedDecks(getDecks());
    setCategories(getCategories());
  };

  const handleFilesSelect = async (files: File[]) => {
    setAppState(AppState.PROCESSING);
    setError(null);
    setLastUploadedAssets(null); // Reset previous assets

    try {
      // Check for JSON deck
      const jsonFile = files.find(f => f.name.endsWith('.json') || f.type === 'application/json');

      if (jsonFile) {
        const text = await jsonFile.text();
        const savedCards = JSON.parse(text) as FlashcardData[];
        if (!Array.isArray(savedCards) || savedCards.length === 0 || !savedCards[0].question) {
           throw new Error("Invalid flashcard deck file.");
        }

        // Create a temporary deck wrapper
        const deck: Deck = {
            id: `imported-${Date.now()}`,
            title: jsonFile.name.replace('.json', ''),
            createdAt: Date.now(),
            cards: savedCards
        };

        setCurrentDeck(deck);
        setAppState(AppState.STUDYING);
        return;
      }

      // Process PDFs and Images
      const contentFiles = files.filter(f => 
        f.type === 'application/pdf' || 
        f.name.endsWith('.pdf') ||
        f.type.startsWith('image/') ||
        /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(f.name)
      );

      if (contentFiles.length === 0) throw new Error("No supported files (PDF or Images) selected.");

      const fileReadPromises = contentFiles.map(file => new Promise<{ mimeType: string; data: string }>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
           const base64String = reader.result as string;
           const base64Data = base64String.split(',')[1];
           // Ensure mimeType is valid. If file.type is empty (sometimes happens), try to guess or default
           let mimeType = file.type;
           if (!mimeType) {
             if (file.name.endsWith('.pdf')) mimeType = 'application/pdf';
             else if (file.name.match(/\.(jpg|jpeg)$/i)) mimeType = 'image/jpeg';
             else if (file.name.match(/\.png$/i)) mimeType = 'image/png';
             else if (file.name.match(/\.webp$/i)) mimeType = 'image/webp';
             else if (file.name.match(/\.heic$/i)) mimeType = 'image/heic';
             else mimeType = 'application/octet-stream';
           }
           resolve({ mimeType, data: base64Data });
        };
        reader.onerror = () => reject(new Error(`Failed to read file: ${file.name}`));
        reader.readAsDataURL(file);
      }));

      const fileData = await Promise.all(fileReadPromises);

      // Store for regeneration
      setLastUploadedAssets(fileData);

      const generatedCards = await generateFlashcardsFromContent(fileData);

      if (generatedCards.length === 0) {
          throw new Error("Could not generate any flashcards.");
      }

      const defaultTitle = contentFiles.length === 1 
          ? contentFiles[0].name.replace(/\.[^/.]+$/, "") 
          : `Study Session ${new Date().toLocaleDateString()}`;

      const newDeck: Deck = {
          id: `deck-${Date.now()}`,
          title: defaultTitle,
          createdAt: Date.now(),
          cards: generatedCards
      };

      setCurrentDeck(newDeck);
      setAppState(AppState.STUDYING);

    } catch (err) {
      setAppState(AppState.ERROR);
      setError(err instanceof Error ? err.message : "An error occurred.");
    }
  };

  const handleRegenerate = async () => {
    if (!lastUploadedAssets || lastUploadedAssets.length === 0) return;

    setAppState(AppState.PROCESSING);
    setError(null);

    try {
      const generatedCards = await generateFlashcardsFromContent(lastUploadedAssets);

      if (generatedCards.length === 0) {
        throw new Error("Could not regenerate flashcards.");
      }

      // Preserve title if possible, else use existing logic or generic
      const currentTitle = currentDeck?.title || `Regenerated Session`;

      const newDeck: Deck = {
        id: `deck-${Date.now()}`,
        title: currentTitle,
        createdAt: Date.now(),
        cards: generatedCards
      };

      setCurrentDeck(newDeck);
      setAppState(AppState.STUDYING);
      setToast({ message: 'Deck regenerated successfully!', type: 'success' });

    } catch (err) {
      setAppState(AppState.ERROR);
      setError(err instanceof Error ? err.message : "An error occurred during regeneration.");
    }
  };

  const handleSaveToLibrary = () => {
    if (!currentDeck) return;

    const exists = savedDecks.some(d => d.id === currentDeck.id);
    if (exists) {
        setToast({ message: 'This deck is already saved to your library.', type: 'error' });
        return;
    }

    setSaveName(currentDeck.title);
    setSaveCategoryId('');
    setShowSaveModal(true);
  };

  const confirmSaveDeck = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!currentDeck) return;

    const finalTitle = saveName.trim() || currentDeck.title;

    try {
      const deckToSave = { 
        ...currentDeck, 
        title: finalTitle,
        categoryId: saveCategoryId || undefined
      };
      saveDeck(deckToSave);

      setCurrentDeck(deckToSave);
      refreshData();

      setShowSaveModal(false);
      setToast({ message: 'Deck saved successfully!', type: 'success' });
    } catch (e) {
      console.error(e);
      setToast({ message: 'Failed to save deck.', type: 'error' });
    }
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCategoryName.trim()) return;

    const newCategory: Category = {
      id: `cat-${Date.now()}`,
      name: newCategoryName.trim()
    };

    saveCategory(newCategory);
    refreshData();
    setNewCategoryName('');
    setShowCategoryModal(false);
    setToast({ message: 'Category created!', type: 'success' });
  };

  const handleUpdateDeck = (e: React.FormEvent) => {
    e.preventDefault();
    if (!deckToEdit) return;

    try {
      const updatedDeck = {
        ...deckToEdit,
        title: saveName.trim() || deckToEdit.title,
        categoryId: saveCategoryId || undefined
      };

      saveDeck(updatedDeck);
      refreshData();

      // If editing current deck, update state
      if (currentDeck && currentDeck.id === updatedDeck.id) {
        setCurrentDeck(updatedDeck);
      }

      setShowEditDeckModal(false);
      setDeckToEdit(null);
      setToast({ message: 'Deck updated!', type: 'success' });
    } catch (e) {
       setToast({ message: 'Failed to update deck.', type: 'error' });
    }
  };

  const openEditDeckModal = (deck: Deck) => {
    setDeckToEdit(deck);
    setSaveName(deck.title);
    setSaveCategoryId(deck.categoryId || '');
    setShowEditDeckModal(true);
  };

  const confirmDeleteDeck = () => {
    if (deckToDelete) {
      deleteDeck(deckToDelete);
      refreshData();
      setDeckToDelete(null);
      setToast({ message: 'Deck deleted.', type: 'success' });

      if (currentDeck && currentDeck.id === deckToDelete) {
        setCurrentDeck(null);
        if (appState === AppState.STUDYING) {
           setAppState(AppState.LIBRARY);
        }
      }
    }
  };

  const handleDeleteCategory = (id: string) => {
     if(window.confirm("Delete this category? Decks in it will become uncategorized.")) {
       deleteCategory(id);
       refreshData();
       setToast({ message: 'Category deleted.', type: 'success' });
     }
  };

  const handleGoHome = () => {
    setAppState(AppState.IDLE);
    setCurrentDeck(null);
    setLastUploadedAssets(null); // Clear assets when going home
    setError(null);
  };

  const handleGoToLibrary = () => {
    refreshData();
    setAppState(AppState.LIBRARY);
    setLastUploadedAssets(null);
    setError(null);
  };

  const isCurrentDeckSaved = currentDeck 
    ? savedDecks.some(d => d.id === currentDeck.id) 
    : false;

  const canRegenerate = lastUploadedAssets !== null && lastUploadedAssets.length > 0;

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans relative">
      <header className="bg-white border-b border-slate-200 sticky top-0 z-40">
        <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={handleGoHome}>
            <div className="bg-indigo-600 p-1.5 rounded-lg">
              <Brain className="w-6 h-6 text-white" />
            </div>
            <span className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
              FlashMind
            </span>
          </div>

          <div className="flex items-center gap-2 sm:gap-4">
             <button 
                onClick={handleGoToLibrary}
                className={`flex items-center gap-2 px-3 py-2 rounded-lg text-sm font-medium transition-colors
                  ${appState === AppState.LIBRARY 
                    ? 'bg-indigo-50 text-indigo-700' 
                    : 'text-slate-600 hover:text-indigo-600 hover:bg-slate-50'
                  }`}
             >
                <BookOpen className="w-4 h-4" />
                <span className="hidden sm:inline">Library</span>
             </button>

             <div className="h-6 w-[1px] bg-slate-200 hidden sm:block"></div>

             <a href="#" className="text-slate-400 hover:text-slate-600 transition-colors">
               <Github className="w-5 h-5" />
             </a>
          </div>
        </div>
      </header>

      <main className="flex-1 flex flex-col">
        <div className="max-w-5xl mx-auto w-full px-4 sm:px-6 lg:px-8 py-8 md:py-12 flex-1 flex flex-col">

          {appState === AppState.LIBRARY && (
             <Library 
                decks={savedDecks}
                categories={categories}
                onSelectDeck={(d) => { setCurrentDeck(d); setAppState(AppState.STUDYING); }}
                onDeleteDeck={setDeckToDelete}
                onEditDeck={openEditDeckModal}
                onCreateNew={handleGoHome}
                onCreateCategory={() => { setNewCategoryName(''); setShowCategoryModal(true); }}
                onDeleteCategory={handleDeleteCategory}
             />
          )}

          {(appState === AppState.IDLE || appState === AppState.PROCESSING || appState === AppState.ERROR) && (
             <div className="flex-1 flex flex-col items-center justify-center min-h-[500px] animate-in fade-in duration-500">
                <div className="text-center mb-12 max-w-2xl">
                  <h1 className="text-4xl md:text-5xl font-extrabold text-slate-900 tracking-tight mb-4">
                    Turn your PDFs & Images into <br/>
                    <span className="text-indigo-600">Smart Flashcards</span>
                  </h1>
                  <p className="text-lg text-slate-500">
                    Upload your lecture notes, textbooks, or diagrams. 
                    FlashMind combines them to generate interactive study aids instantly.
                  </p>
                </div>

                <div className="w-full">
                  <FileUpload 
                    onFilesSelect={handleFilesSelect} 
                    isLoading={appState === AppState.PROCESSING}
                    error={error}
                  />
                </div>

                <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mt-16 text-left w-full max-w-4xl">
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                      <div className="w-10 h-10 bg-blue-50 rounded-lg flex items-center justify-center mb-4">
                        <Sparkles className="w-5 h-5 text-blue-600" />
                      </div>
                      <h3 className="font-semibold text-slate-900 mb-2">Instant Generation</h3>
                      <p className="text-sm text-slate-500">Drag & drop multiple files (PDFs, Images).</p>
                   </div>
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                      <div className="w-10 h-10 bg-indigo-50 rounded-lg flex items-center justify-center mb-4">
                        <BookOpen className="w-5 h-5 text-indigo-600" />
                      </div>
                      <h3 className="font-semibold text-slate-900 mb-2">Organized Library</h3>
                      <p className="text-sm text-slate-500">Categorize and sort your decks for efficient studying.</p>
                   </div>
                   <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
                      <div className="w-10 h-10 bg-purple-50 rounded-lg flex items-center justify-center mb-4">
                        <Layers className="w-5 h-5 text-purple-600" />
                      </div>
                      <h3 className="font-semibold text-slate-900 mb-2">Study Mode</h3>
                      <p className="text-sm text-slate-500">Spaced repetition and LaTeX support.</p>
                   </div>
                </div>
             </div>
          )}

          {appState === AppState.STUDYING && currentDeck && (
            <div className="flex-1 animate-in slide-in-from-bottom-8 duration-700 fade-in">
              <FlashcardDeck 
                cards={currentDeck.cards} 
                deckTitle={currentDeck.title}
                isSaved={isCurrentDeckSaved}
                canRegenerate={canRegenerate}
                onReset={handleGoHome}
                onSaveToLibrary={handleSaveToLibrary}
                onRegenerate={handleRegenerate}
              />
            </div>
          )}
        </div>
      </main>

      <footer className="bg-white border-t border-slate-200 py-6">
        <div className="max-w-5xl mx-auto px-4 text-center text-sm text-slate-500">
          <p>© {new Date().getFullYear()} FlashMind PDF. Built with Gemini API & React.</p>
        </div>
      </footer>

      {/* Save Deck Modal */}
      {showSaveModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden scale-100 animate-in zoom-in-95 duration-200">
            <div className="p-6">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-900">Save to Library</h3>
                <button onClick={() => setShowSaveModal(false)} className="text-slate-400 hover:text-slate-600">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <form onSubmit={confirmSaveDeck}>
                <div className="mb-4">
                  <label htmlFor="deckName" className="block text-sm font-medium text-slate-700 mb-2">Deck Name</label>
                  <input
                    id="deckName"
                    type="text"
                    value={saveName}
                    onChange={(e) => setSaveName(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    placeholder="e.g., Biology Chapter 1"
                    autoFocus
                  />
                </div>
                <div className="mb-6">
                  <label htmlFor="category" className="block text-sm font-medium text-slate-700 mb-2">Category (Optional)</label>
                  <select
                    id="category"
                    value={saveCategoryId}
                    onChange={(e) => setSaveCategoryId(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                  >
                    <option value="">Uncategorized</option>
                    {categories.map(c => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>
                </div>
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowSaveModal(false)} className="flex-1 px-4 py-2 bg-white border border-slate-200 rounded-xl hover:bg-slate-50">Cancel</button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700">Save Deck</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Edit Deck Modal */}
      {showEditDeckModal && deckToEdit && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-md shadow-2xl overflow-hidden scale-100 animate-in zoom-in-95 duration-200">
            <div className="p-6">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-900">Edit Deck</h3>
                <button onClick={() => setShowEditDeckModal(false)} className="text-slate-400 hover:text-slate-600">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <form onSubmit={handleUpdateDeck}>
                <div className="mb-4">
                  <label className="block text-sm font-medium text-slate-700 mb-2">Deck Name</label>
                  <input
                    type="text"
                    value={saveName}
                    onChange={(e) => setSaveName(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                  />
                </div>
                <div className="mb-6">
                  <label className="block text-sm font-medium text-slate-700 mb-2">Category</label>
                  <select
                    value={saveCategoryId}
                    onChange={(e) => setSaveCategoryId(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none bg-white"
                  >
                    <option value="">Uncategorized</option>
                    {categories.map(c => (
                      <option key={c.id} value={c.id}>{c.name}</option>
                    ))}
                  </select>
                </div>
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowEditDeckModal(false)} className="flex-1 px-4 py-2 bg-white border border-slate-200 rounded-xl hover:bg-slate-50">Cancel</button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700">Update</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Create Category Modal */}
      {showCategoryModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden scale-100 animate-in zoom-in-95 duration-200">
            <div className="p-6">
              <div className="flex justify-between items-center mb-4">
                <h3 className="text-xl font-bold text-slate-900">New Category</h3>
                <button onClick={() => setShowCategoryModal(false)} className="text-slate-400 hover:text-slate-600">
                  <X className="w-5 h-5" />
                </button>
              </div>
              <form onSubmit={handleCreateCategory}>
                <div className="mb-6">
                  <label className="block text-sm font-medium text-slate-700 mb-2">Category Name</label>
                  <input
                    type="text"
                    value={newCategoryName}
                    onChange={(e) => setNewCategoryName(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-300 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none"
                    placeholder="e.g., Mathematics"
                    autoFocus
                  />
                </div>
                <div className="flex gap-3">
                  <button type="button" onClick={() => setShowCategoryModal(false)} className="flex-1 px-4 py-2 bg-white border border-slate-200 rounded-xl hover:bg-slate-50">Cancel</button>
                  <button type="submit" className="flex-1 px-4 py-2 bg-indigo-600 text-white rounded-xl hover:bg-indigo-700">Create</button>
                </div>
              </form>
            </div>
          </div>
        </div>
      )}

      {/* Delete Deck Confirmation Modal */}
      {deckToDelete && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-slate-900/50 backdrop-blur-sm p-4 animate-in fade-in duration-200">
          <div className="bg-white rounded-2xl w-full max-w-sm shadow-2xl overflow-hidden scale-100 animate-in zoom-in-95 duration-200">
            <div className="p-6 text-center">
              <div className="w-12 h-12 bg-red-100 rounded-full flex items-center justify-center mx-auto mb-4">
                <Trash2 className="w-6 h-6 text-red-600" />
              </div>
              <h3 className="text-xl font-bold text-slate-900 mb-2">Delete Deck?</h3>
              <p className="text-slate-500 mb-6">
                Are you sure you want to delete this deck? This action cannot be undone.
              </p>

              <div className="flex gap-3">
                <button onClick={() => setDeckToDelete(null)} className="flex-1 px-4 py-2 bg-white border border-slate-200 rounded-xl hover:bg-slate-50">Cancel</button>
                <button onClick={confirmDeleteDeck} className="flex-1 px-4 py-2 bg-red-600 text-white rounded-xl hover:bg-red-700">Delete</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notification */}
      {toast && (
        <div className="fixed bottom-6 right-6 z-50 animate-in slide-in-from-bottom-5 fade-in duration-300">
          <div className={`flex items-center gap-3 px-4 py-3 rounded-lg shadow-lg text-white ${
            toast.type === 'success' ? 'bg-slate-800' : 'bg-red-600'
          }`}>
            {toast.type === 'success' ? <CheckCircle className="w-5 h-5 text-green-400" /> : <AlertCircle className="w-5 h-5 text-white" />}
            <p className="font-medium text-sm">{toast.message}</p>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { RotateCcw, Shuffle, Layers, Check, X, Repeat, Trophy, Download, Bookmark, BookmarkCheck, FileSpreadsheet, FileJson, RefreshCw } from 'lucide-react';
import ReactMarkdown from 'react-markdown';
import remarkMath from 'remark-math';
import rehypeKatex from 'rehype-katex';
import { FlashcardData } from '../types';

interface FlashcardDeckProps {
  cards: FlashcardData[];
  deckTitle?: string;
  isSaved?: boolean;
  canRegenerate?: boolean;
  onReset: () => void;
  onSaveToLibrary: () => void;
  onRegenerate?: () => void;
}

const FlashcardDeck: React.FC<FlashcardDeckProps> = ({ 
  cards: initialCards, 
  deckTitle, 
  isSaved = false, 
  canRegenerate = false,
  onReset, 
  onSaveToLibrary,
  onRegenerate
}) => {
  // We manage a queue of cards to study
  const [queue, setQueue] = useState<FlashcardData[]>(initialCards);
  const [completedCount, setCompletedCount] = useState(0);
  const [isFlipped, setIsFlipped] = useState(false);
  const [totalCards] = useState(initialCards.length);

  // When the queue changes (new card), ensure it starts face up (question side)
  useEffect(() => {
    setIsFlipped(false);
  }, [queue]);

  const handleFlip = () => {
    setIsFlipped(!isFlipped);
  };

  const handleShuffle = () => {
    const shuffled = [...queue].sort(() => Math.random() - 0.5);
    setQueue(shuffled);
    setIsFlipped(false);
  };

  const handleRestart = () => {
    setQueue(initialCards);
    setCompletedCount(0);
    setIsFlipped(false);
  };

  const handleDownloadJson = () => {
    const dataStr = JSON.stringify(initialCards, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${deckTitle || 'flashcards'}-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const handleDownloadCsv = () => {
    const headers = ['Question', 'Answer', 'Category'];
    const rows = initialCards.map(card => {
      const escape = (text: string) => {
        if (!text) return '""';
        return `"${text.replace(/"/g, '""')}"`;
      };
      return [
        escape(card.question),
        escape(card.answer),
        escape(card.category || '')
      ].join(',');
    });

    const csvContent = [headers.join(','), ...rows].join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${deckTitle || 'flashcards'}-${new Date().toISOString().slice(0, 10)}.csv`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const markCorrect = (e: React.MouseEvent) => {
    e.stopPropagation();
    setCompletedCount(prev => prev + 1);
    setQueue(prev => prev.slice(1));
    setIsFlipped(false);
  };

  const markIncorrect = (e: React.MouseEvent) => {
    e.stopPropagation();
    setQueue(prev => {
      const current = prev[0];
      const rest = prev.slice(1);
      return [...rest, current];
    });
    setIsFlipped(false);
  };

  // Helper function to convert \( \) and \[ \] to $ and $$ for remark-math compatibility
  // This allows the app to render the math while keeping the original format for CSV export
  const formatLatexForDisplay = (text: string) => {
    if (!text) return '';
    // Replace \[ ... \] with $$ ... $$ for block math
    // We use a function replacement to avoid issues with nested groups if any (though regex is simple here)
    let formatted = text.replace(/\\\[([\s\S]*?)\\\]/g, (_, content) => `$$${content}$$`);

    // Replace \( ... \) with $ ... $ for inline math
    formatted = formatted.replace(/\\\(([\s\S]*?)\\\)/g, (_, content) => `$${content}$`);

    return formatted;
  };

  // Completion State
  if (queue.length === 0) {
    return (
      <div className="w-full max-w-2xl mx-auto flex flex-col items-center justify-center min-h-[500px] text-center p-8 animate-in zoom-in-50 duration-500">
        <div className="w-24 h-24 bg-yellow-100 rounded-full flex items-center justify-center mb-6">
          <Trophy className="w-12 h-12 text-yellow-600" />
        </div>
        <h2 className="text-3xl font-bold text-slate-900 mb-2">Session Complete!</h2>
        <p className="text-slate-500 mb-8 max-w-md">
          You've successfully reviewed all {totalCards} flashcards from this document.
        </p>

        <div className="flex flex-col sm:flex-row gap-4 w-full max-w-sm">
          <button
            onClick={handleRestart}
            className="flex-1 px-6 py-3 bg-indigo-600 text-white rounded-xl font-medium hover:bg-indigo-700 transition-colors flex items-center justify-center gap-2"
          >
            <RotateCcw className="w-4 h-4" />
            Study Again
          </button>

          {canRegenerate && onRegenerate && (
            <button
              onClick={onRegenerate}
              className="flex-1 px-6 py-3 bg-amber-50 text-amber-700 border border-amber-200 rounded-xl font-medium hover:bg-amber-100 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw className="w-4 h-4" />
              Regenerate
            </button>
          )}

          <button
            onClick={onReset}
            className="flex-1 px-6 py-3 bg-white border border-slate-200 text-slate-700 rounded-xl font-medium hover:bg-slate-50 transition-colors flex items-center justify-center gap-2"
          >
            <Layers className="w-4 h-4" />
            New File
          </button>
        </div>
      </div>
    );
  }

  const currentCard = queue[0];
  const progress = (completedCount / totalCards) * 100;

  return (
    <div className="w-full max-w-2xl mx-auto flex flex-col h-full min-h-[600px]">
      {/* Header Controls */}
      <div className="flex items-center justify-between mb-6 px-4">
        <div className="flex items-center gap-3">
          <button 
            onClick={onReset}
            className="text-sm font-medium text-slate-500 hover:text-indigo-600 flex items-center gap-1 transition-colors"
          >
            <Layers className="w-4 h-4" />
            New
          </button>
          {canRegenerate && onRegenerate && (
            <button 
              onClick={onRegenerate}
              className="text-sm font-medium text-amber-600 hover:text-amber-700 flex items-center gap-1 transition-colors ml-2"
              title="Redo generation if content is missing or formatted poorly"
            >
              <RefreshCw className="w-3.5 h-3.5" />
              Regenerate
            </button>
          )}
          {deckTitle && (
            <span className="hidden sm:block text-sm font-semibold text-slate-300">|</span>
          )}
          {deckTitle && (
             <span className="hidden sm:block text-sm font-semibold text-slate-700 truncate max-w-[150px]">
               {deckTitle}
             </span>
          )}
        </div>

        <div className="flex items-center gap-2">
           <button 
            onClick={onSaveToLibrary}
            className={`p-2 rounded-full transition-all flex items-center gap-2 px-3
              ${isSaved 
                ? 'text-green-600 bg-green-50 cursor-default' 
                : 'text-indigo-600 bg-indigo-50 hover:bg-indigo-100 hover:shadow-sm'
              }`}
            title={isSaved ? "Saved to Library" : "Save to Library"}
            disabled={isSaved}
          >
            {isSaved ? <BookmarkCheck className="w-4 h-4" /> : <Bookmark className="w-4 h-4" />}
            <span className="text-xs font-bold whitespace-nowrap">{isSaved ? 'Saved' : 'Save to Library'}</span>
          </button>

           <div className="h-4 w-[1px] bg-slate-200 mx-1"></div>

           <button 
            onClick={handleDownloadCsv}
            className="p-2 text-slate-400 hover:text-green-600 hover:bg-green-50 rounded-full transition-all"
            title="Download CSV"
          >
            <FileSpreadsheet className="w-4 h-4" />
          </button>

           <button 
            onClick={handleDownloadJson}
            className="p-2 text-slate-400 hover:text-amber-600 hover:bg-amber-50 rounded-full transition-all"
            title="Download JSON"
          >
            <FileJson className="w-4 h-4" />
          </button>

          <button 
            onClick={handleShuffle}
            className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-all"
            title="Shuffle Remaining Cards"
          >
            <Shuffle className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Mastery Progress Bar */}
      <div className="w-full h-2 bg-slate-100 rounded-full mb-8 overflow-hidden flex">
        <div 
          className="h-full bg-green-500 transition-all duration-500 ease-out"
          style={{ width: `${progress}%` }}
          title="Mastered"
        ></div>
         <div 
          className="h-full bg-slate-200 transition-all duration-300"
          style={{ width: `${100 - progress}%` }}
          title="Remaining"
        ></div>
      </div>

      {/* Card Container */}
      <div className="flex-1 flex flex-col justify-center perspective-1000 relative">
        <div 
          className="relative w-full aspect-[4/3] cursor-pointer group"
          onClick={handleFlip}
        >
          <div 
            key={currentCard.id} /* Key forces re-render of animation when card changes */
            className={`
              w-full h-full relative transform-style-3d transition-transform duration-500 ease-in-out shadow-xl hover:shadow-2xl rounded-3xl
              ${isFlipped ? 'rotate-y-180' : ''}
            `}
          >
            {/* Front of Card (Question) */}
            <div className="absolute w-full h-full backface-hidden bg-white rounded-3xl p-8 md:p-12 flex flex-col items-center justify-center text-center border border-slate-100 overflow-y-auto custom-scrollbar">
              <span className="absolute top-6 left-6 text-xs font-bold tracking-wider text-indigo-500 uppercase">
                Question
              </span>
              {currentCard.category && (
                <span className="absolute top-6 right-6 text-xs font-medium text-slate-400 bg-slate-100 px-3 py-1 rounded-full">
                  {currentCard.category}
                </span>
              )}
              <div className="w-full text-xl md:text-3xl font-bold text-slate-800 leading-relaxed select-none">
                <ReactMarkdown
                  remarkPlugins={[remarkMath]}
                  rehypePlugins={[rehypeKatex]}
                  components={{
                    p: ({node, ...props}) => <p className="mb-4 last:mb-0" {...props} />
                  }}
                >
                  {formatLatexForDisplay(currentCard.question)}
                </ReactMarkdown>
              </div>
              <p className="absolute bottom-8 text-sm text-slate-400 font-medium opacity-0 group-hover:opacity-100 transition-opacity">
                Tap to reveal answer
              </p>
            </div>

            {/* Back of Card (Answer) */}
            <div className="absolute w-full h-full backface-hidden rotate-y-180 bg-slate-900 rounded-3xl p-8 md:p-12 flex flex-col items-center justify-center text-center text-white overflow-y-auto custom-scrollbar">
              <span className="absolute top-6 left-6 text-xs font-bold tracking-wider text-slate-400 uppercase">
                Answer
              </span>
              <div className="w-full text-lg md:text-2xl font-medium leading-relaxed mb-8 select-none">
                <ReactMarkdown
                  remarkPlugins={[remarkMath]}
                  rehypePlugins={[rehypeKatex]}
                  components={{
                    p: ({node, ...props}) => <p className="mb-4 last:mb-0" {...props} />
                  }}
                >
                  {formatLatexForDisplay(currentCard.answer)}
                </ReactMarkdown>
              </div>

              {/* Study Controls - Only visible on back */}
              <div className="absolute bottom-8 flex gap-4 w-full px-8 justify-center">
                 <button
                   onClick={markIncorrect}
                   className="flex-1 bg-red-500/20 hover:bg-red-500/30 border border-red-500/50 text-red-200 py-3 rounded-xl font-medium flex items-center justify-center gap-2 transition-all hover:scale-105"
                 >
                   <Repeat className="w-4 h-4" />
                   Needs Review
                 </button>
                 <button
                   onClick={markCorrect}
                   className="flex-1 bg-green-500 hover:bg-green-600 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg shadow-green-900/20 transition-all hover:scale-105"
                 >
                   <Check className="w-5 h-5" />
                   Got it
                 </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Instructions Footer */}
      <div className="mt-8 text-center text-slate-400 text-sm">
        {!isFlipped ? (
           <p>Tap card to show answer</p>
        ) : (
           <p>Rate your knowledge to continue</p>
        )}
      </div>
    </div>
  );
};

export default FlashcardDeck;

import { GoogleGenAI, Type } from "@google/genai";
import { FlashcardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean JSON string with regex
const cleanJsonString = (str: string): string => {
  // Remove markdown code blocks if present
  let cleaned = str.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  // Replace unescaped backslashes that are likely part of LaTeX
  // We want to find a backslash \ that is NOT:
  // 1. Preceded by another backslash (avoid escaping \\)
  // 2. Followed by a valid JSON escape character (", \, /, b, f, n, r, t, u)
  // And replace it with \\
  // This handles cases where the model outputs "\omega" (invalid) instead of "\\omega" (valid)
  return cleaned.replace(/(?<!\\)\\(?!["\\/bfnrtu])/g, "\\\\");
};

export const generateFlashcardsFromContent = async (
  files: { mimeType: string; data: string }[],
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          answer: {
            type: Type.STRING,
            description: "The answer. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          category: {
            type: Type.STRING,
            description: "Category tag."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached documents (PDFs) and images deeply. 
      Create a comprehensive set of flashcards based STRICTLY on the content found in the uploaded files.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}

      Instructions:
      1. STRICT ADHERENCE TO SOURCE: Use ONLY the information provided in the documents.
      2. CARD COUNT: Generate 20 to 40 high-quality flashcards. Prioritize accuracy and valid formatting over quantity.
      3. FORMATTING (CRITICAL):
         - You are outputting a raw JSON string. 
         - **DOUBLE ESCAPE ALL BACKSLASHES** used in LaTeX. 
         - To write a LaTeX start tag like \\( , you MUST write "\\\\(" in the JSON string.
         - To write a LaTeX end tag like \\) , you MUST write "\\\\)" in the JSON string.
         - Example: "question": "Solve for \\\\( x \\\\) in \\\\( x^2 = 4 \\\\)"
         - For Chemistry \\ce{}, write "\\\\ce{...}".
         - Escape all double quotes inside strings (e.g. \\").
         - DO NOT use real line breaks inside strings. Use \\n for line breaks.
      4. CONTENT DENSITY: Group related information into single, comprehensive cards. DO NOT atomize concepts into tiny separate cards. If a topic has connected details (e.g., steps, properties, causes & effects), include them in one card to provide full context.
      5. STRICTLY GENERATE THE FLASHCARDS IN THE SAME LANGUAGE AS THE SOURCE TEXT.
      6. Output pure JSON.
    `;

    // Construct the parts array
    const contentParts = files.map(file => ({
      inlineData: {
        data: file.data,
        mimeType: file.mimeType || "application/pdf", 
      },
    }));

    // Add the text prompt at the end
    contentParts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: contentParts,
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        maxOutputTokens: 8192, 
      },
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    let parsedData: any[] = [];

    try {
        // 1. Try parsing the response directly (after basic markdown cleanup)
        const simpleClean = jsonText.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");
        parsedData = JSON.parse(simpleClean);
    } catch (e1) {
        console.warn("Direct JSON parse failed, attempting regex cleanup...", e1);
        try {
            // 2. Try aggressive backslash cleaning for LaTeX
            const aggressiveClean = cleanJsonString(jsonText);
            parsedData = JSON.parse(aggressiveClean);
        } catch (e2) {
            console.warn("Cleanup parse failed, checking for truncation...", e2);
            // 3. Last resort: Try to salvage truncated JSON
             // If the response was truncated (max tokens), it might end abruptly.
             // We look for the last closed object "}," and close the array.
             // Regex to find the last valid object closing
             const lastObjectEnd = jsonText.lastIndexOf("},");

             if (lastObjectEnd !== -1) {
                 // Take everything up to the last "}," (inclusive), then add "]"
                 const salvaged = jsonText.substring(0, lastObjectEnd + 1) + "]";

                 try {
                      // We also need to clean the salvaged string
                      const cleanedSalvaged = cleanJsonString(salvaged);
                      parsedData = JSON.parse(cleanedSalvaged);
                 } catch (e3) {
                     console.error("Salvage failed:", e3);
                     // Provide the raw text for debugging in console but throw user error
                     throw new Error("Failed to process the AI response. The generated content was not valid JSON.");
                 }
             } else {
                 throw new Error("Failed to process the AI response. The generated content was not valid JSON.");
             }
        }
    }

    // Add IDs to the cards for React keys
    return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
      ...card,
      id: `card-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Upload, FileText, Loader2, AlertCircle, X, Plus, Layers, FileJson, Image as ImageIcon, MessageSquare } from 'lucide-react';

interface FileUploadProps {
  onFilesSelect: (files: File[], instructions: string) => void;
  isLoading: boolean;
  error?: string | null;
}

const FileUpload: React.FC<FileUploadProps> = ({ onFilesSelect, isLoading, error }) => {
  const [selectedFiles, setSelectedFiles] = useState<File[]>([]);
  const [instructions, setInstructions] = useState('');
  const [isDragging, setIsDragging] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
    if (!isLoading) setIsDragging(true);
  };

  const handleDragLeave = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
  };

  const handleDrop = (e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    if (isLoading) return;

    if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
      addFiles(Array.from(e.dataTransfer.files));
    }
  };

  const handleFileInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      addFiles(Array.from(e.target.files));
    }
    if (fileInputRef.current) fileInputRef.current.value = '';
  };

  const addFiles = (newFiles: File[]) => {
    const validFiles = newFiles.filter(file => 
      file.type === 'application/pdf' || 
      file.type === 'application/json' ||
      file.type.startsWith('image/') ||
      file.name.endsWith('.pdf') || 
      file.name.endsWith('.json') ||
      /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(file.name)
    );

    if (validFiles.length === 0 && newFiles.length > 0) {
      alert('Please upload valid PDF files, Images, or a JSON flashcard deck.');
      return;
    }

    const uniqueFiles = validFiles.filter(newFile => 
      !selectedFiles.some(existing => 
        existing.name === newFile.name && existing.size === newFile.size
      )
    );

    setSelectedFiles(prev => [...prev, ...uniqueFiles]);
  };

  const removeFile = (indexToRemove: number) => {
    setSelectedFiles(prev => prev.filter((_, index) => index !== indexToRemove));
  };

  const handleGenerate = () => {
    if (selectedFiles.length > 0) {
      onFilesSelect(selectedFiles, instructions);
    }
  };

  const triggerFileInput = () => {
    if (!isLoading) fileInputRef.current?.click();
  };

  const isJsonDeck = selectedFiles.some(f => f.name.endsWith('.json'));

  const getFileIcon = (file: File) => {
    if (file.name.endsWith('.json')) return <FileJson className="w-4 h-4" />;
    if (file.type.startsWith('image/') || /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(file.name)) return <ImageIcon className="w-4 h-4" />;
    return <FileText className="w-4 h-4" />;
  };

  const getFileColorClass = (file: File) => {
    if (file.name.endsWith('.json')) return 'bg-yellow-50 text-yellow-500';
    if (file.type.startsWith('image/') || /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(file.name)) return 'bg-purple-50 text-purple-500';
    return 'bg-red-50 text-red-500';
  };

  return (
    <div className="w-full max-w-xl mx-auto space-y-6">
      {/* Drop Zone */}
      <div
        className={`relative border-2 border-dashed rounded-2xl p-8 transition-all duration-300 ease-in-out text-center cursor-pointer overflow-hidden
          ${isDragging 
            ? 'border-indigo-500 bg-indigo-50 scale-[1.02]' 
            : 'border-slate-300 hover:border-indigo-400 hover:bg-slate-50 bg-white'
          }
          ${isLoading ? 'opacity-50 pointer-events-none' : ''}
        `}
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        onClick={triggerFileInput}
      >
        <input
          type="file"
          ref={fileInputRef}
          className="hidden"
          accept=".pdf,.json,.jpg,.jpeg,.png,.webp,.heic,.heif,application/pdf,application/json,image/*"
          multiple
          onChange={handleFileInput}
        />

        <div className="flex flex-col items-center justify-center space-y-4">
          <div className={`p-4 rounded-full ${isDragging ? 'bg-indigo-100' : 'bg-slate-100'}`}>
            {isLoading ? (
              <Loader2 className="w-8 h-8 text-indigo-600 animate-spin" />
            ) : (
              <Upload className={`w-8 h-8 ${isDragging ? 'text-indigo-600' : 'text-slate-400'}`} />
            )}
          </div>

          <div className="space-y-2">
            <h3 className="text-lg font-semibold text-slate-700">
              {isLoading ? 'Processing Documents...' : 'Upload PDFs, Images, or Deck'}
            </h3>
            <p className="text-sm text-slate-500 max-w-xs mx-auto">
              {isLoading 
                ? 'Gemini is analyzing your files and creating flashcards.' 
                : 'Drag and drop PDF files, Images, or a saved JSON deck here.'}
            </p>
          </div>
        </div>
      </div>

      {/* Optional Instructions Box - Only show if content files (not just JSON) are selected */}
      {selectedFiles.length > 0 && !isJsonDeck && !isLoading && (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm p-4 space-y-3 animate-in fade-in slide-in-from-top-2">
          <label htmlFor="instructions" className="flex items-center gap-2 text-sm font-semibold text-slate-700">
            <MessageSquare className="w-4 h-4 text-indigo-500" />
            Custom Instructions (Optional)
          </label>
          <textarea
            id="instructions"
            value={instructions}
            onChange={(e) => setInstructions(e.target.value)}
            placeholder="e.g., focus on mathematical formulas, translate to French, or explain key concepts in detail..."
            className="w-full min-h-[100px] px-3 py-2 text-sm border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none resize-none transition-all placeholder:text-slate-400"
          />
        </div>
      )}

      {/* Selected Files List */}
      {selectedFiles.length > 0 && (
        <div className="bg-white rounded-xl border border-slate-200 shadow-sm overflow-hidden animate-in slide-in-from-bottom-2">
          <div className="bg-slate-50 px-4 py-3 border-b border-slate-200 flex justify-between items-center">
            <h4 className="text-xs font-semibold text-slate-500 uppercase tracking-wider">
              Selected Files ({selectedFiles.length})
            </h4>
            {!isLoading && (
              <button 
                onClick={triggerFileInput}
                className="text-indigo-600 hover:text-indigo-700 text-xs font-medium flex items-center gap-1"
              >
                <Plus className="w-3 h-3" /> Add more
              </button>
            )}
          </div>
          <ul className="divide-y divide-slate-100">
            {selectedFiles.map((file, index) => (
              <li key={`${file.name}-${index}`} className="px-4 py-3 flex items-center justify-between group hover:bg-slate-50 transition-colors">
                <div className="flex items-center gap-3 overflow-hidden">
                  <div className={`p-2 rounded-lg shrink-0 ${getFileColorClass(file)}`}>
                    {getFileIcon(file)}
                  </div>
                  <div className="min-w-0">
                    <p className="text-sm font-medium text-slate-700 truncate">{file.name}</p>
                    <p className="text-xs text-slate-400">{(file.size / 1024 / 1024).toFixed(2)} MB</p>
                  </div>
                </div>
                {!isLoading && (
                  <button 
                    onClick={(e) => { e.stopPropagation(); removeFile(index); }}
                    className="text-slate-400 hover:text-red-500 hover:bg-red-50 p-2 rounded-full transition-all"
                    title="Remove file"
                  >
                    <X className="w-4 h-4" />
                  </button>
                )}
              </li>
            ))}
          </ul>
        </div>
      )}

      {/* Generate Button */}
      {selectedFiles.length > 0 && !isLoading && (
        <button
          onClick={handleGenerate}
          className={`w-full py-4 bg-gradient-to-r text-white rounded-xl font-bold shadow-lg transition-all active:scale-[0.99] flex items-center justify-center gap-2
             ${isJsonDeck 
               ? 'from-emerald-500 to-teal-500 shadow-emerald-200 hover:shadow-xl' 
               : 'from-indigo-600 to-purple-600 shadow-indigo-200 hover:shadow-xl hover:scale-[1.01]'
             }
          `}
        >
          {isJsonDeck ? (
             <>
               <FileJson className="w-5 h-5" />
               Load Saved Deck
             </>
          ) : (
             <>
               <Layers className="w-5 h-5" />
               Generate Flashcards
             </>
          )}
        </button>
      )}

      {error && (
        <div className="p-4 bg-red-50 border border-red-200 rounded-xl flex items-start gap-3 text-red-700 animate-in fade-in slide-in-from-bottom-2">
          <AlertCircle className="w-5 h-5 shrink-0 mt-0.5" />
          <p className="text-sm">{error}</p>
        </div>
      )}
    </div>
  );
};

export default FileUpload;

import React, { useState, useEffect } from 'react';
import { Brain, Sparkles, Github, Layers, BookOpen, CheckCircle, AlertCircle, X, Trash2, Edit2, Plus, Folder } from 'lucide-react';
import FileUpload from './components/FileUpload';
import FlashcardDeck from './components/FlashcardDeck';
import Library from './components/Library';
import { AppState, Deck, FlashcardData, Category } from './types';
import { generateFlashcardsFromContent } from './services/geminiService';
import { saveDeck, getDecks, deleteDeck, getCategories, saveCategory, deleteCategory } from './services/storageService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [currentDeck, setCurrentDeck] = useState<Deck | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [savedDecks, setSavedDecks] = useState<Deck[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);

  // Store the raw file data and instructions to allow regeneration
  const [lastUploadedAssets, setLastUploadedAssets] = useState<{ mimeType: string; data: string }[] | null>(null);
  const [lastInstructions, setLastInstructions] = useState<string>('');

  // UI State for Modals and Toasts
  const [showSaveModal, setShowSaveModal] = useState(false);
  const [showCategoryModal, setShowCategoryModal] = useState(false);
  const [showEditDeckModal, setShowEditDeckModal] = useState(false);

  const [deckToDelete, setDeckToDelete] = useState<string | null>(null);
  const [deckToEdit, setDeckToEdit] = useState<Deck | null>(null);

  const [saveName, setSaveName] = useState('');
  const [saveCategoryId, setSaveCategoryId] = useState<string>('');

  const [newCategoryName, setNewCategoryName] = useState('');

  const [toast, setToast] = useState<{message: string, type: 'success' | 'error'} | null>(null);

  // Load data on mount
  useEffect(() => {
    refreshData();
  }, []);

  // Auto-dismiss toast
  useEffect(() => {
    if (toast) {
      const timer = setTimeout(() => setToast(null), 3000);
      return () => clearTimeout(timer);
    }
  }, [toast]);

  const refreshData = () => {
    setSavedDecks(getDecks());
    setCategories(getCategories());
  };

  const handleFilesSelect = async (files: File[], instructions: string = '') => {
    setAppState(AppState.PROCESSING);
    setError(null);
    setLastUploadedAssets(null);
    setLastInstructions(instructions);

    try {
      // Check for JSON deck
      const jsonFile = files.find(f => f.name.endsWith('.json') || f.type === 'application/json');

      if (jsonFile) {
        const text = await jsonFile.text();
        const savedCards = JSON.parse(text) as FlashcardData[];
        if (!Array.isArray(savedCards) || savedCards.length === 0 || !savedCards[0].question) {
           throw new Error("Invalid flashcard deck file.");
        }

        const deck: Deck = {
            id: `imported-${Date.now()}`,
            title: jsonFile.name.replace('.json', ''),
            createdAt: Date.now(),
            cards: savedCards
        };

        setCurrentDeck(deck);
        setAppState(AppState.STUDYING);
        return;
      }

      // Process PDFs and Images
      const contentFiles = files.filter(f => 
        f.type === 'application/pdf' || 
        f.name.endsWith('.pdf') ||
        f.type.startsWith('image/') ||
        /\.(jpg|jpeg|png|webp|heic|heif)$/i.test(f.name)
      );

      if (contentFiles.length === 0) throw new Error("No supported files (PDF or Images) selected.");

      const fileReadPromises = contentFiles.map(file => new Promise<{ mimeType: string; data: string }>((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = () => {
           const base64String = reader.result as string;
           const base64Data = base64String.split(',')[1];
           let mimeType = file.type;
           if (!mimeType) {
             if (file.name.endsWith('.pdf')) mimeType = 'application/pdf';
             else if (file.name.match(/\.(jpg|jpeg)$/i)) mimeType = 'image/jpeg';
             else if (file.name.match(/\.png$/i)) mimeType = 'image/png';
             else if (file.name.match(/\.webp$/i)) mimeType = 'image/webp';
             else if (file.name.match(/\.heic$/i)) mimeType = 'image/heic';
             else mimeType = 'application/octet-stream';
           }
           resolve({ mimeType, data: base64Data });
        };
        reader.onerror = () => reject(new Error(`Failed to read file: ${file.name}`));
        reader.readAsDataURL(file);
      }));

      const fileData = await Promise.all(fileReadPromises);
      setLastUploadedAssets(fileData);

      const generatedCards = await generateFlashcardsFromContent(fileData, instructions);

      if (generatedCards.length === 0) {
          throw new Error("Could not generate any flashcards.");
      }

      const defaultTitle = contentFiles.length === 1 
          ? contentFiles[0].name.replace(/\.[^/.]+$/, "") 
          : `Study Session ${new Date().toLocaleDateString()}`;

      const newDeck: Deck = {
          id: `deck-${Date.now()}`,
          title: defaultTitle,
          createdAt: Date.now(),
          cards: generatedCards
      };

      setCurrentDeck(newDeck);
      setAppState(AppState.STUDYING);

    } catch (err) {
      setAppState(AppState.ERROR);
      setError(err instanceof Error ? err.message : "An error occurred.");
    }
  };

  const handleRegenerate = async () => {
    if (!lastUploadedAssets || lastUploadedAssets.length === 0) return;

    setAppState(AppState.PROCESSING);
    setError(null);

    try {
      // Use stored instructions for regeneration
      const generatedCards = await generateFlashcardsFromContent(lastUploadedAssets, lastInstructions);

      if (generatedCards.length === 0) {
        throw new Error("Could not regenerate flashcards.");
      }

      const currentTitle = currentDeck?.title || `Regenerated Session`;

      const newDeck: Deck = {
        id: `deck-${Date.now()}`,
        title: currentTitle,
        createdAt: Date.now(),
        cards: generatedCards
      };

      setCurrentDeck(newDeck);
      setAppState(AppState.STUDYING);
      setToast({ message: 'Deck regenerated successfully!', type: 'success' });

    } catch (err) {
      setAppState(AppState.ERROR);
      setError(err instanceof Error ? err.message : "An error occurred during regeneration.");
    }
  };

  const handleSaveToLibrary = () => {
    if (!currentDeck) return;

    const exists = savedDecks.some(d => d.id === currentDeck.id);
    if (exists) {
        setToast({ message: 'This deck is already saved to your library.', type: 'error' });
        return;
    }

    setSaveName(currentDeck.title);
    setSaveCategoryId('');
    setShowSaveModal(true);
  };

  const confirmSaveDeck = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!currentDeck) return;

    const finalTitle = saveName.trim() || currentDeck.title;

    try {
      const deckToSave = { 
        ...currentDeck, 
        title: finalTitle,
        categoryId: saveCategoryId || undefined
      };
      saveDeck(deckToSave);

      setCurrentDeck(deckToSave);
      refreshData();

      setShowSaveModal(false);
      setToast({ message: 'Deck saved successfully!', type: 'success' });
    } catch (e) {
      console.error(e);
      setToast({ message: 'Failed to save deck.', type: 'error' });
    }
  };

  const handleCreateCategory = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newCategoryName.trim()) return;

    const newCategory: Category = {
      id: `cat-${Date.now()}`,
      name: newCategoryName.trim()
    };

    saveCategory(newCategory);
    refreshData();
    setNewCategoryName('');
    setShowCategoryModal(false);
    setToast({ message: 'Category created!', type: 'success' });
  };

  const handleUpdateDeck = (e: React.FormEvent) => {
    e.preventDefault();
    if (!deckToEdit) return;

    try {
      const updatedDeck = {
        ...deckToEdit,
        title: saveName.trim() || deckToEdit.title,
        categoryId: saveCategoryId || undefined
      };

      saveDeck(updatedDeck);
      refreshData();

      if (currentDeck && currentDeck.id === updatedDeck.id) {
        setCurrentDeck(updatedDeck);
      }

      setShowEditDeckModal(false);
      setDeckToEdit(null);
      setToast({ message: 'Deck updated!', type: 'success' });
    } catch (e) {
       setToast({ message: 'Failed to update deck.', type: 'error' });
    }
  };

  const openEditDeckModal = (deck: Deck) => {
    setDeckToEdit(deck);
    setSaveName(deck.title);
    setSaveCategoryId(deck.categoryId || '');
    setShowEditDeckModal(true);
  };

  const confirmDeleteDeck = () => {
    if (deckToDelete) {
      deleteDeck(deckToDelete);
      refreshData();
      setDeckToDelete(null);
      setToast({ message: 'Deck deleted.', type: 'success' });

      if (currentDeck && currentDeck.id === deckToDelete) {
        setCurrentDeck(null);
        if (appState === AppState.STUDYING) {
           setAppState(AppState.LIBRARY);
        }
      }
    }
  };

  const handleDeleteCategory = (id: string) => {
     if(window.confirm("Delete this category? Decks in it will become uncategorized.")) {
       deleteCategory(id);
       refreshData();
       setToast({ message: 'Category deleted.', type: 'success' });
     }
  };

  const handleGoHome = () => {
    setAppState(AppState.IDLE);
    setCurrentDeck(null);
    setLastUploadedAssets(null);
    setLastInstructions('');
    setError(null);
  };

  const handleGoToLibrary = () => {
    refreshData();
    setAppState(AppState.LIBRARY);
    setLastUploadedAssets(null);
    setLastInstructions('');
    setError(null);
  };

  const isCurrentDeckSaved = currentDeck 
    ? savedDecks.some(d => d.id === currentDeck.id) 
    : false;

