import { GoogleGenAI, Type } from "@google/genai";
import { FlashcardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean JSON string with regex
const cleanJsonString = (str: string): string => {
  // Remove markdown code blocks if present
  let cleaned = str.replace(/```json/g, "").replace(/```/g, "");

  // Replace unescaped backslashes that are likely part of LaTeX
  // We want to find a backslash \ that is NOT:
  // 1. Preceded by another backslash (avoid escaping \\)
  // 2. Followed by a valid JSON escape character (", \, /, b, f, n, r, t, u)
  // And replace it with \\
  // This handles cases where the model outputs "\omega" (invalid) instead of "\\omega" (valid)
  return cleaned.replace(/(?<!\\)\\(?!["\\/bfnrtu])/g, "\\\\");
};

export const generateFlashcardsFromContent = async (
  files: { mimeType: string; data: string }[],
  topicContext?: string
): Promise<FlashcardData[]> => {
  try {
    const modelId = "gemini-3-flash-preview"; 

    // Define the schema for strict JSON output
    const responseSchema = {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          question: {
            type: Type.STRING,
            description: "The question. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          answer: {
            type: Type.STRING,
            description: "The answer. Use double escaped LaTeX for math (e.g. \\\\( x \\\\))."
          },
          category: {
            type: Type.STRING,
            description: "Category tag."
          }
        },
        required: ["question", "answer"],
      },
    };

    const prompt = `
      Analyze the attached documents (PDFs) and images deeply. 
      Create a comprehensive set of flashcards based STRICTLY on the content found in the uploaded files.
      ${topicContext ? `Focus specifically on this topic: ${topicContext}` : ''}

      Instructions:
      1. STRICT ADHERENCE TO SOURCE: Use ONLY the information provided in the documents.
      2. CARD COUNT: Generate 20 to 40 high-quality flashcards. Prioritize accuracy and valid formatting over quantity.
      3. FORMATTING (CRITICAL):
         - You are outputting a raw JSON string. 
         - **DOUBLE ESCAPE ALL BACKSLASHES** used in LaTeX. 
         - To write a LaTeX start tag like \\( , you MUST write "\\\\(" in the JSON string.
         - To write a LaTeX end tag like \\) , you MUST write "\\\\)" in the JSON string.
         - Example: "question": "Solve for \\\\( x \\\\) in \\\\( x^2 = 4 \\\\)"
         - For Chemistry \\ce{}, write "\\\\ce{...}".
         - Escape all double quotes inside strings (e.g. \\").
         - DO NOT use real line breaks inside strings. Use \\n for line breaks.
      4. CONTENT DENSITY: Group related information into single, comprehensive cards. DO NOT atomize concepts into tiny separate cards. If a topic has connected details (e.g., steps, properties, causes & effects), include them in one card to provide full context.
      5. STRICTLY GENERATE THE FLASHCARDS IN THE SAME LANGUAGE AS THE SOURCE TEXT.
      6. Output pure JSON. Do not wrap in markdown blocks. No \`\`\`json tags.
    `;

    // Construct the parts array
    const contentParts = files.map(file => ({
      inlineData: {
        data: file.data,
        mimeType: file.mimeType || "application/pdf", 
      },
    }));

    // Add the text prompt at the end
    contentParts.push({ text: prompt } as any);

    const response = await ai.models.generateContent({
      model: modelId,
      contents: {
        parts: contentParts,
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        maxOutputTokens: 8192, 
      },
    });

    const jsonText = response.text;
    if (!jsonText) {
      throw new Error("No data returned from Gemini.");
    }

    let parsedData: any[] = [];

    try {
        // 1. Extract JSON array if surrounded by text (handling markdown wrappers or intro text)
        let cleanText = jsonText;
        const startIndex = jsonText.indexOf('[');
        const endIndex = jsonText.lastIndexOf(']');

        if (startIndex !== -1 && endIndex !== -1 && endIndex > startIndex) {
            cleanText = jsonText.substring(startIndex, endIndex + 1);
        }

        // 2. Try parsing directly
        parsedData = JSON.parse(cleanText);
    } catch (e1) {
        console.warn("Direct JSON parse failed, attempting regex cleanup...", e1);
        try {
            // 3. Try aggressive backslash cleaning for LaTeX
            // Re-extract potential JSON from original text just in case
            let cleanText = jsonText;
            const startIndex = jsonText.indexOf('[');
            const endIndex = jsonText.lastIndexOf(']');
            if (startIndex !== -1 && endIndex !== -1 && endIndex > startIndex) {
                cleanText = jsonText.substring(startIndex, endIndex + 1);
            } else {
                // If no brackets found, try cleaning the whole string (maybe single object or truncated)
                cleanText = jsonText; 
            }

            const aggressiveClean = cleanJsonString(cleanText);
            parsedData = JSON.parse(aggressiveClean);
        } catch (e2) {
            console.error("Final parse failed:", e2);
            // Throw a user-friendly error
            throw new Error("Failed to process the AI response. The generated content was not valid JSON. Please try regenerating.");
        }
    }

    // Add IDs to the cards for React keys
    return parsedData.map((card: Omit<FlashcardData, 'id'>, index: number) => ({
      ...card,
      id: `card-${Date.now()}-${index}`
    }));

  } catch (error) {
    console.error("Error generating flashcards:", error);
    throw error;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { FlashcardData } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// Helper to clean and repair JSON string
const cleanAndRepairJson = (str: string): string => {
  let cleaned = str.trim();

  // 1. Remove markdown code blocks if present
  cleaned = cleaned.replace(/^```json\s*/, "").replace(/^```\s*/, "").replace(/\s*```$/, "");

  // 2. Replace unescaped backslashes that are likely part of LaTeX
  // We want to find a backslash \ that is NOT:
  // - Preceded by another backslash (avoid escaping \\)
  // - Followed by a valid JSON escape character (", \, /, b, f, n, r, t, u)
  // And replace it with \\
  cleaned = cleaned.replace(/(?<!\\)\\(?!["\\/bfnrtu])/g, "\\\\");

  // 3. Handle Truncation (Unterminated String/Array)
  // If it starts with [ but doesn't end with ], it's likely truncated.
  if (cleaned.startsWith("[") && !cleaned.endsWith("]")) {
      // Find the last valid object closing "},"
      const lastObjectSeparator = cleaned.lastIndexOf("},");

      if (lastObjectSeparator !== -1) {
          // Cut off everything after the last "}," and close the array
          // We include the "}" at lastObjectSeparator + 1
          cleaned = cleaned.substring(0, lastObjectSeparator + 1) + "]";
      } else {
          // Fallback: Find the last "}" even if no comma follows
          const lastClosingBrace = cleaned.lastIndexOf("}");
          if (lastClosingBrace !== -1) {
             // Check if we are inside a string (rough check) - not doing complex state machine here
             // but usually "}" at top level indicates object end. 
             // Safest is to rely on "}," but if only 1 item exists and is cut off, we might just fail.
             // Let's try to close it.
             cleaned = cleaned.substring(0, lastClosingBrace + 1) + "]";
          }
      }
  }

  return cleaned;
};

